#[tokio::test]
async fn peer_ingress_runtime_refresh_quiesces_carrier_and_fences_stale_runtime() {
    struct DropSignal(Arc<AtomicBool>);

    impl Drop for DropSignal {
        fn drop(&mut self) {
            self.0.store(true, Ordering::SeqCst);
        }
    }

    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    let runtime_a: Arc<dyn CommsRuntime> = Arc::new(FakeDrainRuntime::idle());
    let runtime_b: Arc<dyn CommsRuntime> = Arc::new(FakeDrainRuntime::idle());
    assert!(
        adapter
            .update_peer_ingress_context(&session_id, true, Some(Arc::clone(&runtime_a)))
            .await
            .expect("attach first runtime")
    );

    let carrier_dropped = Arc::new(AtomicBool::new(false));
    let carrier_started = Arc::new(Notify::new());
    let carrier = tokio::spawn({
        let carrier_dropped = Arc::clone(&carrier_dropped);
        let carrier_started = Arc::clone(&carrier_started);
        async move {
            let _drop_signal = DropSignal(carrier_dropped);
            carrier_started.notify_one();
            std::future::pending::<()>().await;
        }
    });
    carrier_started.notified().await;
    let rotation_slot = {
        let sessions = adapter.sessions.read().await;
        Arc::clone(
            &sessions
                .get(&session_id)
                .expect("registered session entry")
                .supervisor_rotation_task,
        )
    };
    assert!(
        rotation_slot
            .install(
                "refresh-carrier".to_string(),
                Arc::clone(&runtime_a),
                carrier,
            )
            .await
    );

    assert!(
        adapter
            .update_peer_ingress_context(&session_id, true, Some(Arc::clone(&runtime_b)))
            .await
            .expect("refresh to second runtime")
    );
    assert!(
        carrier_dropped.load(Ordering::SeqCst),
        "runtime replacement must abort and join the old rotation carrier"
    );
    assert!(
        !adapter
            .peer_ingress_runtime_is_current(&session_id, &runtime_a)
            .await
            .expect("inspect stale runtime fence"),
        "old runtime must fail the generated-id and drain-slot fence"
    );
    assert!(
        adapter
            .peer_ingress_runtime_is_current(&session_id, &runtime_b)
            .await
            .expect("inspect current runtime fence"),
        "replacement runtime must own both generated and mechanical authority"
    );

    adapter
        .unregister_session(&session_id)
        .await
        .expect("session should unregister cleanly");
}

/// Regression (0.7.2): `unregister_session` must BOUND its comms-drain await.
///
/// The two-phase drain aborts the comms-drain task and awaits its quiescence.
/// The runtime-loop handle is bounded (grace + abort), but the comms-drain
/// handle was awaited UNBOUNDED — so an external member (e.g. a TCP transport
/// drain) whose task does not observe the cooperative abort promptly wedged
/// teardown forever (the `external_tcp_production_drain` smoke hung past 900s).
/// This is a regular (non-live, CI-gated) guard: a drain task that blocks its
/// worker and ignores abort must NOT stall `unregister_session`.
#[tokio::test(flavor = "multi_thread")]
async fn unregister_session_bounds_an_unquiescing_comms_drain() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    let comms_runtime: Arc<dyn CommsRuntime> = Arc::new(FakeDrainRuntime::idle());

    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");

    // A drain task that blocks its worker thread and does NOT honor tokio's
    // cooperative abort, modelling a transport drain parked in a non-yielding
    // operation. It auto-releases well above the teardown grace so that a
    // regressed (unbounded) await terminates the test rather than hanging
    // runtime shutdown.
    let (release_tx, release_rx) = std::sync::mpsc::channel::<()>();
    let stuck = tokio::spawn(async move {
        tokio::task::block_in_place(move || {
            let _ = release_rx.recv_timeout(Duration::from_secs(10));
        });
    });
    {
        let mut sessions = adapter.sessions.write().await;
        let entry = sessions
            .get_mut(&session_id)
            .expect("register_session must have created the entry");
        {
            let mut authority = entry
                .dsl_authority
                .lock()
                .unwrap_or_else(std::sync::PoisonError::into_inner);
            crate::meerkat_machine::dsl::MeerkatMachineMutator::apply(
                &mut *authority,
                crate::meerkat_machine::dsl::MeerkatMachineInput::SpawnDrain {
                    mode: crate::meerkat_machine::dsl::DrainMode::from(
                        CommsDrainMode::PersistentHost,
                    ),
                },
            )
            .expect("test drain spawn authority should accept");
        }
        entry.drain_slot.install_task(comms_runtime, stuck);
    }

    // `COMMS_DRAIN_GRACE` (~2s) must bound the owned teardown saga; pre-fix
    // this awaited the stuck handle unbounded (~10s) and the 5s outer bound
    // would elapse. The independently-owned saga and caller grace expire at
    // roughly the same time, so the surface may either observe completion or
    // the typed in-progress receipt while the saga finishes in the background.
    let first_result = crate::tokio::time::timeout(
        Duration::from_secs(5),
        adapter.unregister_session(&session_id),
    )
    .await
    .expect("unregister_session must not hang on an unquiescing comms drain");

    // Release the modelled-stuck worker so the test does not leak it.
    let _ = release_tx.send(());

    match first_result {
        Ok(()) => {}
        Err(RuntimeDriverError::UnregisterInProgress { runtime_id }) => {
            assert_eq!(runtime_id, runtime_id_for_session(&session_id));
            crate::tokio::time::timeout(
                Duration::from_secs(5),
                adapter.unregister_session(&session_id),
            )
            .await
            .expect("the retained unregister saga must remain joinable")
            .expect("the retained unregister saga should finish after the drain releases");
        }
        Err(error) => panic!("unexpected bounded unregister result: {error}"),
    }
    assert!(
        !adapter.contains_session(&session_id).await,
        "bounded comms teardown must eventually remove the registration"
    );
}

#[tokio::test]
async fn unregister_session_deletes_persisted_ops_lifecycle_epoch() {
    let store = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let adapter = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();
    let runtime_id = runtime_id_for_session(&session_id);
    let stale_epoch = meerkat_core::RuntimeEpochId::new();
    let stale_cursor = meerkat_core::EpochCursorState::new();
    let stale_snapshot = crate::ops_lifecycle::RuntimeOpsLifecycleRegistry::new()
        .capture_persistence_snapshot(stale_epoch.clone(), &stale_cursor)
        .unwrap();

    crate::store::RuntimeStore::persist_ops_lifecycle(store.as_ref(), &runtime_id, &stale_snapshot)
        .await
        .expect("test snapshot should persist");

    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    adapter
        .unregister_session(&session_id)
        .await
        .expect("unregister should delete the persisted ops lifecycle epoch");

    assert!(
        crate::store::RuntimeStore::load_ops_lifecycle(store.as_ref(), &runtime_id)
            .await
            .expect("store should load")
            .is_none(),
        "unregister ends the runtime epoch and must remove its durable ops snapshot"
    );

    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    let sessions = adapter.sessions.read().await;
    let rebound_epoch = sessions
        .get(&session_id)
        .expect("session should re-register")
        .epoch_id
        .clone();
    assert_ne!(
        rebound_epoch, stale_epoch,
        "durable rebind must mint a fresh epoch after unregister"
    );
}

#[tokio::test]
async fn unregister_session_delete_failure_retains_live_entry_and_stale_snapshot() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store = Arc::new(RuntimeCommitAtomicityStore::fail_delete_ops_lifecycle_once(
        Arc::clone(&inner),
    ));
    let adapter = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();
    let runtime_id = runtime_id_for_session(&session_id);
    let stale_epoch = meerkat_core::RuntimeEpochId::new();
    let stale_cursor = meerkat_core::EpochCursorState::new();
    let stale_snapshot = crate::ops_lifecycle::RuntimeOpsLifecycleRegistry::new()
        .capture_persistence_snapshot(stale_epoch, &stale_cursor)
        .unwrap();

    crate::store::RuntimeStore::persist_ops_lifecycle(inner.as_ref(), &runtime_id, &stale_snapshot)
        .await
        .expect("test snapshot should persist");

    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    let first_error = adapter
        .unregister_session(&session_id)
        .await
        .expect_err("the injected delete failure must be returned to the caller");
    assert!(
        first_error
            .to_string()
            .contains("synthetic delete_ops_lifecycle failure"),
        "the surfaced unregister error must retain the store failure: {first_error}"
    );

    assert!(
        adapter.contains_session(&session_id).await,
        "failed DeleteSnapshot teardown must retain the live entry instead of forgetting it"
    );
    assert!(
        crate::store::RuntimeStore::load_ops_lifecycle(inner.as_ref(), &runtime_id)
            .await
            .expect("store should load")
            .is_some(),
        "failed DeleteSnapshot teardown must not hide the stale durable snapshot"
    );
    assert_eq!(
        crate::store::load_runtime_state(inner.as_ref(), &runtime_id)
            .await
            .expect("store should load lifecycle"),
        Some(RuntimeState::Stopped),
        "failed atomic finalization must retain the completed-drain stop anchor beside stale ops"
    );
    let retry_anchor = adapter
        .session_dsl_state(&session_id)
        .await
        .expect("failed finalization must retain generated retry authority");
    assert_eq!(
        retry_anchor.registration_phase,
        mm_dsl::RegistrationPhase::Draining
    );
    assert!(!retry_anchor.unregister_runtime_loop_drain_pending);
    assert!(!retry_anchor.unregister_comms_drain_exit_pending);
    assert!(!retry_anchor.unregister_completion_waiter_drain_pending);
    let post_failure_accept = <MeerkatMachine as SessionServiceRuntimeExt>::accept_input(
        &adapter,
        &session_id,
        make_prompt("must not enter drained runtime"),
    )
    .await;
    match post_failure_accept {
        Err(_) => {}
        Ok(outcome) => panic!(
            "failed DeleteSnapshot rollback must leave the retained entry retry-only, got {outcome:?}"
        ),
    }
    let post_failure_progress_accept = <MeerkatMachine as SessionServiceRuntimeExt>::accept_input(
        &adapter,
        &session_id,
        make_progress_input("must-not-enter-drained-runtime"),
    )
    .await;
    match post_failure_progress_accept {
        Err(_) => {}
        Ok(outcome) => panic!(
            "failed DeleteSnapshot rollback must reject wake-effect peer progress too, got {outcome:?}"
        ),
    }
    let post_failure_without_wake_accept = adapter
        .accept_input_without_wake(
            &session_id,
            make_progress_input("must-not-enter-drained-runtime-without-wake"),
        )
        .await;
    match post_failure_without_wake_accept {
        Err(_) => {}
        Ok(outcome) => panic!(
            "failed DeleteSnapshot rollback must reject no-wake ingress too, got {outcome:?}"
        ),
    }

    adapter
        .unregister_session(&session_id)
        .await
        .expect("retry should succeed after the one-shot delete failure");
    assert!(
        !adapter.contains_session(&session_id).await,
        "second unregister should remove the entry after delete succeeds"
    );
    assert!(
        crate::store::RuntimeStore::load_ops_lifecycle(inner.as_ref(), &runtime_id)
            .await
            .expect("store should load")
            .is_none(),
        "successful retry must delete stale ops lifecycle snapshot"
    );
}

#[tokio::test]
async fn unregister_session_unsupported_atomic_finalization_fails_closed() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store = Arc::new(
        RuntimeCommitAtomicityStore::unsupported_unregister_finalization(Arc::clone(&inner)),
    );
    let adapter = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();
    let runtime_id = runtime_id_for_session(&session_id);
    let stale_snapshot = crate::ops_lifecycle::RuntimeOpsLifecycleRegistry::new()
        .capture_persistence_snapshot(
            meerkat_core::RuntimeEpochId::new(),
            &meerkat_core::EpochCursorState::new(),
        )
        .unwrap();
    let stale_snapshot_bytes = serde_json::to_vec(&stale_snapshot).unwrap();

    crate::store::RuntimeStore::persist_ops_lifecycle(inner.as_ref(), &runtime_id, &stale_snapshot)
        .await
        .unwrap();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    let lifecycle_before = crate::store::load_machine_lifecycle(inner.as_ref(), &runtime_id)
        .await
        .unwrap()
        .expect("registered lifecycle must be durable before unregister");

    let error = adapter
        .unregister_session(&session_id)
        .await
        .expect_err("a store without atomic unregister support must fail closed");
    assert!(
        error
            .to_string()
            .contains("Unsupported store operation: commit_unregister_finalization"),
        "the required atomic store contract must surface directly: {error}"
    );
    assert!(adapter.contains_session(&session_id).await);
    assert_eq!(
        store.delete_ops_lifecycle_calls(),
        0,
        "unregister must never fall back to the legacy independent delete hook"
    );
    let lifecycle_after = crate::store::load_machine_lifecycle(inner.as_ref(), &runtime_id)
        .await
        .unwrap()
        .expect("unsupported finalization must retain a retryable lifecycle anchor");
    assert_eq!(
        lifecycle_after.runtime_state(),
        RuntimeState::Stopped,
        "external cleanup cannot be rolled back to live Idle when finalization is unsupported"
    );
    assert_eq!(
        lifecycle_after.binding(),
        lifecycle_before.binding(),
        "failed finalization must not rewrite the runtime binding"
    );
    let unregister_progress = lifecycle_after
        .unregister_progress()
        .expect("completed drain must retain typed unregister progress");
    assert!(!unregister_progress.runtime_loop_drain_pending());
    assert!(!unregister_progress.comms_drain_exit_pending());
    assert!(!unregister_progress.completion_waiter_drain_pending());
    let persisted_ops = crate::store::RuntimeStore::load_ops_lifecycle(inner.as_ref(), &runtime_id)
        .await
        .unwrap()
        .expect("unsupported atomic finalization must retain the old ops epoch");
    assert_eq!(
        serde_json::to_vec(&persisted_ops).unwrap(),
        stale_snapshot_bytes,
        "unsupported atomic finalization must leave exact ops bytes unchanged"
    );
}

#[tokio::test]
async fn unregister_session_unknown_commit_outcome_retries_without_durable_rollback() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store = Arc::new(RuntimeCommitAtomicityStore::commit_then_report_unknown(
        Arc::clone(&inner),
    ));
    let adapter = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();
    let runtime_id = runtime_id_for_session(&session_id);
    let stale_snapshot = crate::ops_lifecycle::RuntimeOpsLifecycleRegistry::new()
        .capture_persistence_snapshot(
            meerkat_core::RuntimeEpochId::new(),
            &meerkat_core::EpochCursorState::new(),
        )
        .unwrap();
    crate::store::RuntimeStore::persist_ops_lifecycle(inner.as_ref(), &runtime_id, &stale_snapshot)
        .await
        .unwrap();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    let finalizations_before = store.unregister_finalization_calls();

    let error = adapter
        .unregister_session(&session_id)
        .await
        .expect_err("synthetic lost acknowledgement must retain a retry anchor");
    assert!(matches!(
        error,
        RuntimeDriverError::UnregisterFinalizationOutcomeUnknown { .. }
    ));
    assert!(adapter.contains_session(&session_id).await);
    let terminal_retry_anchor = adapter
        .session_dsl_state(&session_id)
        .await
        .expect("ambiguous finalization must retain terminal generated authority");
    assert_eq!(
        terminal_retry_anchor.registration_phase,
        mm_dsl::RegistrationPhase::Queuing
    );
    assert!(
        terminal_retry_anchor.session_id.is_none(),
        "ambiguous finalization must not restore the draining projection"
    );
    assert!(
        adapter
            .sessions
            .read()
            .await
            .get(&session_id)
            .is_some_and(|entry| entry.pending_unregister_finalization.is_some()),
        "ambiguous finalization must retain its exact in-memory retry witness"
    );
    assert_eq!(
        store.unregister_finalization_calls(),
        finalizations_before + 1,
        "the initial saga must issue exactly one atomic unregister finalization"
    );
    assert_eq!(
        store
            .successful_unregister_progress()
            .iter()
            .filter(|progress| **progress == Some((false, false, false)))
            .count(),
        1,
        "an unknown atomic outcome must not emit a duplicate completed-drain rollback write"
    );
    assert_eq!(store.delete_ops_lifecycle_calls(), 0);
    assert!(
        crate::store::RuntimeStore::load_ops_lifecycle(inner.as_ref(), &runtime_id)
            .await
            .unwrap()
            .is_none(),
        "the synthetic committed side of the ambiguous outcome retired the old ops epoch"
    );
    let lifecycle_after_unknown = crate::store::load_machine_lifecycle(inner.as_ref(), &runtime_id)
        .await
        .unwrap();
    let progress_writes_after_unknown = store.successful_unregister_progress().len();
    let finalizations_after_unknown = store.unregister_finalization_calls();
    let all_commit_calls_after_unknown = store.commit_machine_lifecycle_calls();

    let register_error = adapter
        .register_session(session_id.clone())
        .await
        .expect_err("registration must not revive an ambiguous terminal retry anchor");
    assert!(register_error.to_string().contains("outcome is unknown"));
    let bindings_error = adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect_err("binding preparation must not revive an ambiguous terminal retry anchor");
    assert!(bindings_error.to_string().contains("outcome is unknown"));
    let attach_error = adapter
        .ensure_session_with_executor(session_id.clone(), Box::new(RuntimeParityNoopExecutor))
        .await
        .expect_err("executor attachment must not revive an ambiguous terminal retry anchor");
    assert!(matches!(
        attach_error,
        RuntimeDriverError::UnregisterFinalizationOutcomeUnknown { .. }
    ));
    let retire_error =
        <MeerkatMachine as SessionServiceRuntimeExt>::retire_runtime(adapter.as_ref(), &session_id)
            .await
            .expect_err("lifecycle controls must freeze behind an ambiguous finalization");
    assert!(retire_error.to_string().contains("outcome is unknown"));
    assert_eq!(
        adapter
            .session_dsl_state(&session_id)
            .await
            .expect("fenced operations must retain generated terminal authority"),
        terminal_retry_anchor,
        "fenced operations must not mutate the exact terminal retry anchor"
    );
    assert_eq!(
        crate::store::load_machine_lifecycle(inner.as_ref(), &runtime_id)
            .await
            .unwrap(),
        lifecycle_after_unknown,
        "fenced operations must not overwrite the possibly committed lifecycle snapshot"
    );
    assert_eq!(
        store.commit_machine_lifecycle_calls(),
        all_commit_calls_after_unknown,
        "fenced operations must issue no ordinary or atomic lifecycle writes"
    );
    assert_eq!(
        store.successful_unregister_progress().len(),
        progress_writes_after_unknown,
        "fenced operations must not append unregister progress"
    );

    store
        .fail_unregister_finalization
        .store(true, Ordering::SeqCst);
    adapter
        .unregister_session(&session_id)
        .await
        .expect_err("a failed idempotent finalization retry must retain its witness");
    assert!(adapter.contains_session(&session_id).await);
    assert!(
        adapter
            .sessions
            .read()
            .await
            .get(&session_id)
            .is_some_and(|entry| entry.pending_unregister_finalization.is_some()),
        "every failed exact retry must retain the pending finalization witness"
    );
    let anchor_after_failed_retry = adapter
        .session_dsl_state(&session_id)
        .await
        .expect("failed retry must retain terminal generated authority");
    assert_eq!(
        anchor_after_failed_retry.registration_phase,
        mm_dsl::RegistrationPhase::Queuing
    );
    assert!(anchor_after_failed_retry.session_id.is_none());
    assert_eq!(
        store.unregister_finalization_calls(),
        finalizations_after_unknown + 1,
        "retry must issue only the exact atomic unregister finalization"
    );
    assert_eq!(
        store.successful_unregister_progress().len(),
        progress_writes_after_unknown,
        "retry must never emit an ordinary lifecycle progress write"
    );

    adapter
        .unregister_session(&session_id)
        .await
        .expect("idempotent retry must converge after the lost acknowledgement");
    assert!(!adapter.contains_session(&session_id).await);
    assert_eq!(
        crate::store::load_machine_lifecycle(inner.as_ref(), &runtime_id)
            .await
            .unwrap(),
        lifecycle_after_unknown,
        "retry must preserve the exact committed final lifecycle"
    );
    assert_eq!(
        store.unregister_finalization_calls(),
        finalizations_after_unknown + 2,
        "converging retry must issue only one more atomic finalization"
    );
    assert_eq!(
        store.successful_unregister_progress().len(),
        progress_writes_after_unknown,
        "converging retry must not overwrite terminal truth through the ordinary lifecycle path"
    );
    assert!(
        crate::store::RuntimeStore::load_ops_lifecycle(inner.as_ref(), &runtime_id)
            .await
            .unwrap()
            .is_none()
    );
}

#[tokio::test]
async fn unregister_session_finalization_persist_failure_restores_retry_anchor() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store = Arc::new(RuntimeCommitAtomicityStore::pass_through(Arc::clone(
        &inner,
    )));
    let adapter = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();
    let runtime_id = runtime_id_for_session(&session_id);

    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    let finalizations_before_unregister = store.unregister_finalization_calls();
    store
        .fail_unregister_finalization
        .store(true, Ordering::SeqCst);

    let first_error = adapter
        .unregister_session(&session_id)
        .await
        .expect_err("the injected finalization persist failure must be returned to the caller");
    assert!(
        first_error
            .to_string()
            .contains("synthetic unregister finalization failure"),
        "the surfaced unregister error must retain the finalization persist failure: {first_error}"
    );
    assert!(
        adapter.contains_session(&session_id).await,
        "failed lifecycle persistence must retain the live entry for retry"
    );
    let retry_anchor = adapter
        .session_dsl_state(&session_id)
        .await
        .expect("failed unregister must retain generated retry authority");
    assert_eq!(
        retry_anchor.registration_phase,
        mm_dsl::RegistrationPhase::Draining,
        "rollback must restore the completed-drain state accepted by final-unregister retry"
    );
    assert!(!retry_anchor.unregister_runtime_loop_drain_pending);
    assert!(!retry_anchor.unregister_comms_drain_exit_pending);
    assert!(!retry_anchor.unregister_completion_waiter_drain_pending);
    assert!(
        adapter
            .sessions
            .read()
            .await
            .get(&session_id)
            .is_some_and(|entry| entry.pending_unregister_finalization.is_none()),
        "an ordinary rolled-back finalization failure must clear the ambiguous-outcome witness"
    );
    assert_eq!(
        crate::store::load_runtime_state(inner.as_ref(), &runtime_id)
            .await
            .expect("load rolled-back lifecycle"),
        Some(RuntimeState::Stopped),
        "rollback persistence must restore completed-drain stop authority"
    );
    assert_eq!(
        store.unregister_finalization_calls(),
        finalizations_before_unregister + 1,
        "the first saga must attempt exactly one atomic finalization"
    );
    assert_eq!(
        store
            .successful_unregister_progress()
            .iter()
            .filter(|progress| **progress == Some((false, false, false)))
            .count(),
        2,
        "the failed finalization must be followed by one exact completed-drain rollback persist"
    );

    adapter
        .unregister_session(&session_id)
        .await
        .expect("retry should succeed after the one-shot finalization persist failure");
    assert_eq!(
        store.unregister_finalization_calls(),
        finalizations_before_unregister + 2,
        "retry must issue exactly one new atomic finalization"
    );
    assert!(
        !adapter.contains_session(&session_id).await,
        "second unregister should consume the retained retry anchor"
    );
}

#[tokio::test]
async fn unregister_retry_repersist_live_feedback_before_advancing_teardown() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store = Arc::new(RuntimeCommitAtomicityStore::pass_through(Arc::clone(
        &inner,
    )));
    let adapter = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();
    let runtime_id = runtime_id_for_session(&session_id);
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");

    let calls_before = store.commit_machine_lifecycle_calls();
    let progress_before = store.successful_unregister_progress().len();
    // BeginUnregister persists on the first call. Fail the immediately
    // following write, after RuntimeLoopStoppedForUnregister has already
    // changed live generated authority.
    store.fail_commit_machine_lifecycle_on_call(calls_before + 2);
    let error = adapter
        .unregister_session(&session_id)
        .await
        .expect_err("the first live-feedback progress write should fail once");
    assert!(
        error
            .to_string()
            .contains("synthetic commit_machine_lifecycle failure"),
        "unexpected progress-persist failure: {error}"
    );

    let live = adapter
        .session_dsl_state(&session_id)
        .await
        .expect("failed saga must retain its live Draining retry anchor");
    assert!(!live.unregister_runtime_loop_drain_pending);
    assert!(live.unregister_comms_drain_exit_pending);
    assert!(live.unregister_completion_waiter_drain_pending);
    let durable = crate::store::load_machine_lifecycle(inner.as_ref(), &runtime_id)
        .await
        .expect("load durable progress")
        .expect("BeginUnregister progress must remain durable");
    let durable_progress = durable
        .unregister_progress()
        .expect("Draining lifecycle must carry typed unregister progress");
    assert!(durable_progress.runtime_loop_drain_pending());
    assert!(durable_progress.comms_drain_exit_pending());
    assert!(durable_progress.completion_waiter_drain_pending());
    let persisted_after_failure = store.successful_unregister_progress();
    assert_eq!(
        &persisted_after_failure[progress_before..],
        &[Some((true, true, true))],
        "the failed feedback write must not masquerade as durable progress"
    );

    adapter
        .unregister_session(&session_id)
        .await
        .expect("the next owned saga should re-persist live progress then finish");
    let progress = store.successful_unregister_progress();
    assert_eq!(
        progress.get(progress_before + 1),
        Some(&Some((false, true, true))),
        "retry must first durably publish the already-live feedback prefix"
    );
    assert!(!adapter.contains_session(&session_id).await);
}

#[tokio::test]
async fn cold_recovery_resumes_typed_v3_unregister_progress() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store = Arc::new(RuntimeCommitAtomicityStore::pass_through(Arc::clone(
        &inner,
    )));
    let first_machine = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();
    let runtime_id = runtime_id_for_session(&session_id);
    first_machine
        .register_session(session_id.clone())
        .await
        .expect("register session on first process");

    let calls_before = store.commit_machine_lifecycle_calls();
    // Persist Begin + runtime-loop disposition, then fail the comms
    // disposition write after its live generated transition. This leaves a
    // real typed partial prefix for a fresh process to recover.
    store.fail_commit_machine_lifecycle_on_call(calls_before + 3);
    first_machine
        .unregister_session(&session_id)
        .await
        .expect_err("partial unregister progress should fail once before process loss");
    let durable_partial = crate::store::load_machine_lifecycle(inner.as_ref(), &runtime_id)
        .await
        .expect("load partial v3 record")
        .expect("partial lifecycle record should exist");
    let durable_partial = durable_partial
        .unregister_progress()
        .expect("Draining v3 record must carry unregister progress");
    assert!(!durable_partial.runtime_loop_drain_pending());
    assert!(durable_partial.comms_drain_exit_pending());
    assert!(durable_partial.completion_waiter_drain_pending());
    drop(first_machine);

    let recovered_machine = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    recovered_machine
        .register_session(session_id.clone())
        .await
        .expect("fresh process should recover the partial Draining epoch");
    let recovered = recovered_machine
        .session_dsl_state(&session_id)
        .await
        .expect("recovered generated unregister authority");
    assert_eq!(
        recovered.registration_phase,
        mm_dsl::RegistrationPhase::Draining
    );
    assert!(!recovered.unregister_runtime_loop_drain_pending);
    assert!(recovered.unregister_comms_drain_exit_pending);
    assert!(recovered.unregister_completion_waiter_drain_pending);

    recovered_machine
        .unregister_session(&session_id)
        .await
        .expect("cold-recovered saga should close only its remaining obligations");
    assert!(!recovered_machine.contains_session(&session_id).await);
    let durable_final = crate::store::load_machine_lifecycle(inner.as_ref(), &runtime_id)
        .await
        .expect("load final lifecycle")
        .expect("final lifecycle record should remain queryable");
    assert_eq!(durable_final.unregister_progress(), None);
    assert_eq!(durable_final.binding().agent_runtime_id(), None);
}

#[tokio::test]
async fn unregister_session_preserves_primary_when_rollback_persist_also_fails() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store = Arc::new(RuntimeCommitAtomicityStore::pass_through(inner));
    let adapter = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();

    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    store
        .fail_unregister_finalization
        .store(true, Ordering::SeqCst);
    store
        .fail_rollback_after_unregister_finalization_failure
        .store(true, Ordering::SeqCst);

    let error = adapter
        .unregister_session(&session_id)
        .await
        .expect_err("terminal and rollback lifecycle persists should both fail");
    let rendered = error.to_string();
    assert!(
        rendered.contains("unregister lifecycle+ops finalization failed"),
        "combined error must retain the primary terminal-persist failure: {rendered}"
    );
    assert!(
        rendered.contains("additionally failed to persist unregister rollback"),
        "combined error must report rollback persistence separately: {rendered}"
    );
    assert!(
        rendered.contains("unregister rollback lifecycle persist failed"),
        "combined error must retain the rollback-persist cause: {rendered}"
    );
    assert!(
        adapter.contains_session(&session_id).await,
        "even a failed rollback persist must retain the in-memory retry anchor"
    );

    adapter
        .unregister_session(&session_id)
        .await
        .expect("retry should consume the restored in-memory anchor once persistence recovers");
}

#[tokio::test]
async fn concurrent_unregister_callers_join_original_drain_result() {
    struct BlockingExecutor {
        apply_started: Arc<Notify>,
        allow_finish: Option<tokio::sync::oneshot::Receiver<()>>,
    }

    #[async_trait::async_trait]
    impl CoreExecutor for BlockingExecutor {
        async fn apply(
            &mut self,
            run_id: RunId,
            primitive: RunPrimitive,
        ) -> Result<CoreApplyOutput, CoreExecutorError> {
            self.apply_started.notify_waiters();
            self.allow_finish
                .take()
                .expect("blocking executor should only apply once")
                .await
                .expect("test release sender should stay alive until apply is released");

            Ok(CoreApplyOutput {
                receipt: RunBoundaryReceiptDraft {
                    run_id,
                    boundary: RunApplyBoundary::RunStart,
                    contributing_input_ids: primitive.contributing_input_ids().to_vec(),
                    conversation_digest: None,
                    message_count: 0,
                },
                session_snapshot: None,
                terminal: None,
            })
        }

        async fn stop_runtime_executor(
            &mut self,
            _reason: String,
        ) -> Result<(), CoreExecutorError> {
            Ok(())
        }

        async fn cancel_after_boundary(
            &mut self,
            _reason: String,
        ) -> Result<(), CoreExecutorError> {
            Ok(())
        }
    }

    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    let apply_started = Arc::new(Notify::new());
    let (allow_finish_tx, allow_finish_rx) = tokio::sync::oneshot::channel();

    adapter
        .register_session_with_executor(
            session_id.clone(),
            Box::new(BlockingExecutor {
                apply_started: Arc::clone(&apply_started),
                allow_finish: Some(allow_finish_rx),
            }),
        )
        .await
        .expect("runtime executor registration should succeed");
    adapter
        .accept_input(&session_id, make_prompt("block unregister drain"))
        .await
        .expect("prompt should start attached runtime");
    tokio::time::timeout(Duration::from_secs(1), apply_started.notified())
        .await
        .expect("runtime should enter blocking apply");

    let first_unregister = tokio::spawn({
        let adapter = Arc::clone(&adapter);
        let session_id = session_id.clone();
        async move { adapter.unregister_session(&session_id).await }
    });
    tokio::time::timeout(Duration::from_secs(1), async {
        loop {
            let state = adapter
                .session_dsl_state(&session_id)
                .await
                .expect("session should still have DSL state");
            if state.registration_phase == mm_dsl::RegistrationPhase::Draining {
                break;
            }
            tokio::time::sleep(Duration::from_millis(10)).await;
        }
    })
    .await
    .expect("first unregister should open the drain window");

    let second_unregister = tokio::spawn({
        let adapter = Arc::clone(&adapter);
        let session_id = session_id.clone();
        async move { adapter.unregister_session(&session_id).await }
    });
    tokio::task::yield_now().await;
    assert!(
        !second_unregister.is_finished(),
        "concurrent unregister must join rather than fabricate an early result"
    );
    assert!(
        adapter.contains_session(&session_id).await,
        "concurrent unregister must not fabricate drain feedback or remove the entry"
    );

    allow_finish_tx
        .send(())
        .expect("blocking executor should still be awaiting release");
    first_unregister
        .await
        .expect("first unregister task should not panic")
        .expect("first unregister should complete cleanly");
    second_unregister
        .await
        .expect("second unregister task should not panic")
        .expect("second unregister should receive the shared clean result");
    assert!(
        !adapter.contains_session(&session_id).await,
        "original unregister should remove the entry after the real drain finishes"
    );
}

#[tokio::test]
async fn unregister_session_retains_terminal_machine_lifecycle_snapshot() {
    let store = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let adapter = Arc::new(MeerkatMachine::persistent(
        store.clone() as Arc<dyn crate::store::RuntimeStore>,
        memory_blob_store(),
    ));
    let session_id = SessionId::new();
    let runtime_id = runtime_id_for_session(&session_id);

    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    crate::traits::RuntimeControlPlane::retire(adapter.as_ref(), &runtime_id)
        .await
        .expect("retire should persist generated terminal lifecycle");
    assert_eq!(
        crate::store::load_runtime_state(store.as_ref(), &runtime_id)
            .await
            .expect("load retired runtime state"),
        Some(RuntimeState::Retired)
    );

    adapter
        .unregister_session(&session_id)
        .await
        .expect("session should unregister cleanly");

    assert!(!adapter.contains_session(&session_id).await);
    assert_eq!(
        crate::store::load_runtime_state(store.as_ref(), &runtime_id)
            .await
            .expect("load runtime state after unregister"),
        Some(RuntimeState::Retired),
        "unregister cleanup must not overwrite generated terminal lifecycle truth with its post-cleanup Idle projection"
    );
    let durable = crate::store::load_machine_lifecycle(store.as_ref(), &runtime_id)
        .await
        .expect("load final retired lifecycle")
        .expect("retained retired lifecycle should remain queryable");
    assert_eq!(
        durable.unregister_progress(),
        None,
        "retired unregister must persist the generated final image, not an unfinished Draining prefix"
    );
    assert_eq!(
        durable.binding().agent_runtime_id(),
        None,
        "retired unregister must clear the stale runtime binding tuple"
    );
}

#[tokio::test]
async fn session_service_runtime_ext_write_side_follows_machine_control_surface() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");

    let state = <MeerkatMachine as SessionServiceRuntimeExt>::runtime_state(&adapter, &session_id)
        .await
        .expect("runtime state should route through the machine seam");
    assert_eq!(state, RuntimeState::Idle);

    let outcome = <MeerkatMachine as SessionServiceRuntimeExt>::accept_input(
        &adapter,
        &session_id,
        make_prompt("service-ext-write-side"),
    )
    .await
    .expect("accept_input should route through the machine seam");
    assert!(
        matches!(outcome, AcceptOutcome::Accepted { .. }),
        "prompt should still be admitted through the SessionServiceRuntimeExt seam"
    );

    let active =
        <MeerkatMachine as SessionServiceRuntimeExt>::list_active_inputs(&adapter, &session_id)
            .await
            .expect("active inputs should still be readable");
    assert_eq!(active.len(), 1, "accepted input should remain active");
    let active_state = <MeerkatMachine as SessionServiceRuntimeExt>::input_state(
        &adapter,
        &session_id,
        &active[0],
    )
    .await
    .expect("input_state should route through the machine seam");
    assert_eq!(
        active_state.map(|stored| stored.seed.phase),
        Some(crate::input_state::InputLifecycleState::Queued),
        "accepted prompt should still be visible through machine-routed input_state"
    );

    let retire_report =
        <MeerkatMachine as SessionServiceRuntimeExt>::retire_runtime(&adapter, &session_id)
            .await
            .expect("retire should route through the machine seam");
    assert_eq!(
        retire_report.inputs_abandoned, 1,
        "retire should still abandon queued work when no runtime loop is attached"
    );
    assert_eq!(retire_report.inputs_pending_drain, 0);

    let reset_report =
        <MeerkatMachine as SessionServiceRuntimeExt>::reset_runtime(&adapter, &session_id)
            .await
            .expect("reset should route through the machine seam");
    assert_eq!(
        reset_report.inputs_abandoned, 0,
        "reset after retire should not find residual queued work"
    );
}

/// M4 (reconciliation query): an idempotency key resolves through the
/// machine-owned admission map to its input's stored state; an unknown key
/// resolves to `None`; a deduplicated resubmission resolves to the ORIGINAL
/// input.
#[tokio::test]
async fn input_state_by_idempotency_key_resolves_machine_owned_binding() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");

    let key = crate::identifiers::IdempotencyKey::new("interaction-42");
    let mut prompt = make_prompt("keyed interaction");
    let prompt_id = prompt.id().clone();
    if let Input::Prompt(inner) = &mut prompt {
        inner.header.idempotency_key = Some(key.clone());
    }
    let outcome =
        <MeerkatMachine as SessionServiceRuntimeExt>::accept_input(&adapter, &session_id, prompt)
            .await
            .expect("keyed prompt should be accepted");
    assert!(matches!(outcome, AcceptOutcome::Accepted { .. }));

    let stored = <MeerkatMachine as SessionServiceRuntimeExt>::input_state_by_idempotency_key(
        &adapter,
        &session_id,
        &key.to_string(),
    )
    .await
    .expect("keyed lookup should route through the machine seam")
    .expect("the admitted input must resolve from its idempotency key");
    assert_eq!(stored.state.input_id, prompt_id);
    assert_eq!(
        stored.seed.phase,
        crate::input_state::InputLifecycleState::Queued
    );

    let missing = <MeerkatMachine as SessionServiceRuntimeExt>::input_state_by_idempotency_key(
        &adapter,
        &session_id,
        "no-such-key",
    )
    .await
    .expect("unknown key lookup should still route through the machine seam");
    assert!(
        missing.is_none(),
        "an unregistered key must resolve to None"
    );

    // A duplicate under the same key dedups; the key keeps resolving to the
    // ORIGINAL input, read-only (the lookup itself never rebinds).
    let mut duplicate = make_prompt("keyed interaction resubmitted");
    if let Input::Prompt(inner) = &mut duplicate {
        inner.header.idempotency_key = Some(key.clone());
    }
    let duplicate_outcome = <MeerkatMachine as SessionServiceRuntimeExt>::accept_input(
        &adapter,
        &session_id,
        duplicate,
    )
    .await
    .expect("duplicate keyed prompt should resolve");
    assert!(matches!(
        duplicate_outcome,
        AcceptOutcome::Deduplicated { .. }
    ));
    let still_original =
        <MeerkatMachine as SessionServiceRuntimeExt>::input_state_by_idempotency_key(
            &adapter,
            &session_id,
            &key.to_string(),
        )
        .await
        .expect("keyed lookup should still succeed after dedup")
        .expect("the binding must still resolve");
    assert_eq!(still_original.state.input_id, prompt_id);
}

/// M4 acceptance: the terminal status of a keyed interaction is queryable
/// AFTER a host restart (new store handle, new machine, session
/// re-registration) — embedders reconcile interrupted work without keeping
/// their own run journal.
#[cfg(all(not(target_arch = "wasm32"), feature = "sqlite-store"))]
#[tokio::test]
async fn input_terminal_status_by_idempotency_key_survives_restart() {
    struct CompletingExecutor;

    #[async_trait::async_trait]
    impl CoreExecutor for CompletingExecutor {
        async fn apply(
            &mut self,
            run_id: RunId,
            primitive: RunPrimitive,
        ) -> Result<CoreApplyOutput, CoreExecutorError> {
            Ok(CoreApplyOutput {
                receipt: meerkat_core::lifecycle::RunBoundaryReceiptDraft {
                    run_id,
                    boundary: meerkat_core::lifecycle::RunApplyBoundary::RunStart,
                    contributing_input_ids: primitive.contributing_input_ids().to_vec(),
                    conversation_digest: None,
                    message_count: 0,
                },
                session_snapshot: None,
                terminal: None,
            })
        }

        async fn cancel_after_boundary(
            &mut self,
            _reason: String,
        ) -> Result<(), CoreExecutorError> {
            Ok(())
        }

        async fn stop_runtime_executor(
            &mut self,
            _reason: String,
        ) -> Result<(), CoreExecutorError> {
            Ok(())
        }
    }

    let dir = tempfile::TempDir::new().expect("temp dir");
    let path = dir.path().join("runtime.sqlite3");
    let store = Arc::new(
        crate::store::SqliteRuntimeStore::new(path.clone()).expect("sqlite runtime store"),
    ) as Arc<dyn crate::store::RuntimeStore>;
    let session_id = SessionId::new();
    let key = crate::identifiers::IdempotencyKey::new("restart-reconcile-1");

    {
        let machine = Arc::new(MeerkatMachine::persistent(
            Arc::clone(&store),
            memory_blob_store(),
        ));
        machine
            .register_session_with_executor(session_id.clone(), Box::new(CompletingExecutor))
            .await
            .expect("runtime executor registration should succeed");

        let mut prompt = make_prompt("keyed interaction to reconcile");
        if let Input::Prompt(inner) = &mut prompt {
            inner.header.idempotency_key = Some(key.clone());
        }
        let (outcome, completion) = machine
            .accept_input_with_completion(&session_id, prompt)
            .await
            .expect("keyed prompt should be accepted");
        assert!(outcome.is_accepted());
        let completion = completion.expect("queued prompt should register completion");
        tokio::time::timeout(Duration::from_secs(2), completion.wait_authorized())
            .await
            .expect("keyed prompt should reach a terminal outcome before restart");

        // Wait until the terminal state is durably visible through the
        // machine seam before simulating the restart.
        tokio::time::timeout(Duration::from_secs(2), async {
            loop {
                let stored =
                    <MeerkatMachine as SessionServiceRuntimeExt>::input_state_by_idempotency_key(
                        &machine,
                        &session_id,
                        &key.to_string(),
                    )
                    .await
                    .expect("keyed lookup should succeed pre-restart");
                if stored
                    .and_then(|stored| stored.seed.terminal_outcome)
                    .is_some()
                {
                    break;
                }
                tokio::time::sleep(Duration::from_millis(10)).await;
            }
        })
        .await
        .expect("keyed prompt should terminalize before restart");
    }
    drop(store);

    let restarted_store = Arc::new(
        crate::store::SqliteRuntimeStore::new(path).expect("sqlite runtime store reopens"),
    ) as Arc<dyn crate::store::RuntimeStore>;
    let restarted = MeerkatMachine::persistent(restarted_store, memory_blob_store());
    restarted
        .register_session(session_id.clone())
        .await
        .expect("session re-registration should recover persisted input states");

    let stored = <MeerkatMachine as SessionServiceRuntimeExt>::input_state_by_idempotency_key(
        &restarted,
        &session_id,
        &key.to_string(),
    )
    .await
    .expect("keyed lookup should route through the machine seam after restart")
    .expect("the recovered binding must resolve after restart");
    assert_eq!(
        stored.seed.terminal_outcome,
        Some(crate::input_state::InputTerminalOutcome::Consumed),
        "the restarted host must be able to read the interaction's terminal status"
    );
    assert!(
        stored.seed.last_run_id.is_some(),
        "the terminal status must carry the resolving run id"
    );
}

/// Shared setup for the restart-first-class terminal-status lane: drive a
/// keyed prompt to its `Consumed` terminal on a persistent machine, wait
/// until the terminal facts (including the resolving run id) are visible
/// through the machine seam, then drop the machine and the store handle.
#[cfg(all(not(target_arch = "wasm32"), feature = "sqlite-store"))]
async fn seed_terminal_keyed_prompt_store() -> (
    tempfile::TempDir,
    PathBuf,
    SessionId,
    IdempotencyKey,
    InputId,
    RunId,
) {
    struct CompletingExecutor;

    #[async_trait::async_trait]
    impl CoreExecutor for CompletingExecutor {
        async fn apply(
            &mut self,
            run_id: RunId,
            primitive: RunPrimitive,
        ) -> Result<CoreApplyOutput, CoreExecutorError> {
            Ok(CoreApplyOutput {
                receipt: meerkat_core::lifecycle::RunBoundaryReceiptDraft {
                    run_id,
                    boundary: meerkat_core::lifecycle::RunApplyBoundary::RunStart,
                    contributing_input_ids: primitive.contributing_input_ids().to_vec(),
                    conversation_digest: None,
                    message_count: 0,
                },
                session_snapshot: None,
                terminal: None,
            })
        }

        async fn cancel_after_boundary(
            &mut self,
            _reason: String,
        ) -> Result<(), CoreExecutorError> {
            Ok(())
        }

        async fn stop_runtime_executor(
            &mut self,
            _reason: String,
        ) -> Result<(), CoreExecutorError> {
            Ok(())
        }
    }

    let dir = tempfile::TempDir::new().expect("temp dir");
    let path = dir.path().join("runtime.sqlite3");
    let store = Arc::new(
        crate::store::SqliteRuntimeStore::new(path.clone()).expect("sqlite runtime store"),
    ) as Arc<dyn crate::store::RuntimeStore>;
    let session_id = SessionId::new();
    let key = crate::identifiers::IdempotencyKey::new("terminal-status-restart-1");

    let machine = Arc::new(MeerkatMachine::persistent(
        Arc::clone(&store),
        memory_blob_store(),
    ));
    machine
        .register_session_with_executor(session_id.clone(), Box::new(CompletingExecutor))
        .await
        .expect("runtime executor registration should succeed");

    let mut prompt = make_prompt("keyed interaction to reconcile after restart");
    let prompt_id = prompt.id().clone();
    if let Input::Prompt(inner) = &mut prompt {
        inner.header.idempotency_key = Some(key.clone());
    }
    let (outcome, completion) = machine
        .accept_input_with_completion(&session_id, prompt)
        .await
        .expect("keyed prompt should be accepted");
    assert!(outcome.is_accepted());
    let completion = completion.expect("queued prompt should register completion");
    tokio::time::timeout(Duration::from_secs(2), completion.wait_authorized())
        .await
        .expect("keyed prompt should reach a terminal outcome before restart");

    // Wait until the terminal state (with its resolving run id) is visible
    // through the machine seam before simulating the restart.
    let run_id = tokio::time::timeout(Duration::from_secs(2), async {
        loop {
            let stored =
                <MeerkatMachine as SessionServiceRuntimeExt>::input_state_by_idempotency_key(
                    &machine,
                    &session_id,
                    &key.to_string(),
                )
                .await
                .expect("keyed lookup should succeed pre-restart");
            if let Some(stored) = stored
                && stored.seed.terminal_outcome.is_some()
                && let Some(run_id) = stored.seed.last_run_id
            {
                break run_id;
            }
            tokio::time::sleep(Duration::from_millis(10)).await;
        }
    })
    .await
    .expect("keyed prompt should terminalize with a bound run id before restart");
    drop(machine);
    drop(store);

    (dir, path, session_id, key, prompt_id, run_id)
}

/// M4 restart-first-class (G1): the terminal status of a keyed interaction is
/// queryable after a host restart WITHOUT registering the session — the
/// durable RuntimeStore witnesses answer directly.
#[cfg(all(not(target_arch = "wasm32"), feature = "sqlite-store"))]
#[tokio::test]
async fn interaction_terminal_status_by_key_survives_restart_without_registration() {
    let (_dir, path, session_id, key, prompt_id, run_id) = seed_terminal_keyed_prompt_store().await;

    let restarted_store = Arc::new(
        crate::store::SqliteRuntimeStore::new(path).expect("sqlite runtime store reopens"),
    ) as Arc<dyn crate::store::RuntimeStore>;
    let restarted = MeerkatMachine::persistent(restarted_store, memory_blob_store());
    // Deliberately NOT registered: the query must answer from the store.
    let sourced = <MeerkatMachine as SessionServiceRuntimeExt>::interaction_terminal_status(
        &restarted,
        &session_id,
        crate::terminal_status::InteractionSelector::IdempotencyKey(key.to_string()),
    )
    .await
    .expect("unregistered durable terminal-status query should succeed")
    .expect("the persisted keyed interaction must resolve without registration");
    assert_eq!(
        sourced.source,
        crate::terminal_status::TerminalWitnessSource::DurableStore,
        "an unregistered session must be answered by the durable witness"
    );
    assert_eq!(sourced.report.input_id, prompt_id);
    assert_eq!(
        sourced.report.terminal,
        Some(crate::input_state::InputTerminalOutcome::Consumed),
    );
    assert_eq!(sourced.report.resolving_run_id, Some(run_id));
    assert_eq!(
        sourced.report.idempotency_key,
        Some(key),
        "the durable report must carry the reconciliation key"
    );
}

/// M4 restart-first-class (G1, shipped-surface fold-in): the EXISTING
/// `input_state_by_idempotency_key` answers from the durable store for an
/// unregistered session instead of failing `NotReady { Destroyed }`.
#[cfg(all(not(target_arch = "wasm32"), feature = "sqlite-store"))]
#[tokio::test]
async fn input_state_by_idempotency_key_falls_back_to_store_when_unregistered() {
    let (_dir, path, session_id, key, prompt_id, _run_id) =
        seed_terminal_keyed_prompt_store().await;

    let restarted_store = Arc::new(
        crate::store::SqliteRuntimeStore::new(path).expect("sqlite runtime store reopens"),
    ) as Arc<dyn crate::store::RuntimeStore>;
    let restarted = MeerkatMachine::persistent(restarted_store, memory_blob_store());
    let stored = <MeerkatMachine as SessionServiceRuntimeExt>::input_state_by_idempotency_key(
        &restarted,
        &session_id,
        &key.to_string(),
    )
    .await
    .expect("unregistered keyed lookup should fall back to the durable store")
    .expect("the persisted binding must resolve without registration");
    assert_eq!(stored.state.input_id, prompt_id);
    assert_eq!(
        stored.seed.terminal_outcome,
        Some(crate::input_state::InputTerminalOutcome::Consumed),
    );
}

/// M4 restart-first-class (G2): a run id captured before the restart resolves
