/// One-canonical-evaluator agreement: after restart + re-registration, the
/// live query and a store-handle-direct `evaluate_run` over
/// `load_input_states` produce identical facts (only the source differs).
#[cfg(all(not(target_arch = "wasm32"), feature = "sqlite-store"))]
#[tokio::test]
async fn live_and_durable_run_terminal_reports_agree_after_recovery() {
    let (_dir, path, session_id, _key, prompt_id, run_id) =
        seed_terminal_keyed_prompt_store().await;

    let restarted_store = Arc::new(
        crate::store::SqliteRuntimeStore::new(path).expect("sqlite runtime store reopens"),
    ) as Arc<dyn crate::store::RuntimeStore>;
    let restarted = MeerkatMachine::persistent(Arc::clone(&restarted_store), memory_blob_store());
    restarted
        .register_session(session_id.clone())
        .await
        .expect("session re-registration should recover persisted input states");

    let live = <MeerkatMachine as SessionServiceRuntimeExt>::run_terminal_status(
        &restarted,
        &session_id,
        &run_id,
    )
    .await
    .expect("live run-status query should succeed");
    assert_eq!(
        live.source,
        crate::terminal_status::TerminalWitnessSource::LiveRuntime,
    );

    let durable_witnesses = restarted_store
        .load_input_states(&runtime_id_for_session(&session_id))
        .await
        .expect("store-handle-direct witness read should succeed");
    let durable = crate::terminal_status::evaluate_run(&run_id, &durable_witnesses);

    assert_eq!(live.report.status, durable.status);
    let fact_projection = |report: &crate::terminal_status::RunTerminalReport| {
        report
            .witnesses
            .iter()
            .map(|witness| {
                (
                    witness.input_id.clone(),
                    witness.phase,
                    witness.terminal.clone(),
                    witness.resolving_run_id.clone(),
                    witness.attempt_count,
                    witness.idempotency_key.clone(),
                )
            })
            .collect::<Vec<_>>()
    };
    assert_eq!(
        fact_projection(&live.report),
        fact_projection(&durable),
        "the single canonical evaluator must produce identical facts from both witnesses"
    );
    assert_eq!(live.report.witnesses[0].input_id, prompt_id);
}

/// Test peer-comms install target that accepts the generated install: the
/// minimal comms runtime surface the field repro needs (the 0.7.19–0.7.23
/// resume-strand class fired `PublishLocalEndpoint` through this seam).
struct AcceptingPeerCommsInstallTarget {
    descriptor: meerkat_core::comms::TrustedPeerDescriptor,
    notify: Arc<tokio::sync::Notify>,
}

impl AcceptingPeerCommsInstallTarget {
    fn new(name: &str, seed: u8) -> Self {
        let pubkey = [seed; 32];
        let peer_id = meerkat_core::comms::PeerId::from_ed25519_pubkey(&pubkey);
        let descriptor = meerkat_core::comms::TrustedPeerDescriptor::unsigned_with_pubkey(
            name,
            peer_id.to_string(),
            pubkey,
            format!("inproc://{name}"),
        )
        .expect("valid peer descriptor");
        Self {
            descriptor,
            notify: Arc::new(tokio::sync::Notify::new()),
        }
    }
}

#[async_trait::async_trait]
impl meerkat_core::agent::CommsRuntime for AcceptingPeerCommsInstallTarget {
    async fn drain_messages(&self) -> Vec<String> {
        Vec::new()
    }

    fn inbox_notify(&self) -> Arc<tokio::sync::Notify> {
        Arc::clone(&self.notify)
    }

    fn peer_id(&self) -> Option<meerkat_core::comms::PeerId> {
        Some(self.descriptor.peer_id)
    }

    fn public_key_bytes(&self) -> Option<[u8; 32]> {
        Some(self.descriptor.pubkey)
    }

    fn comms_name(&self) -> Option<String> {
        Some(self.descriptor.name.as_str().to_string())
    }

    fn advertised_address(&self) -> Option<String> {
        Some(self.descriptor.address.to_string())
    }
}

impl meerkat_core::handles::PeerCommsInstallTarget for AcceptingPeerCommsInstallTarget {
    fn install_generated_peer_comms_handle(
        &self,
        _install: meerkat_core::handles::GeneratedPeerCommsInstall,
    ) -> Result<(), String> {
        Ok(())
    }
}

fn test_llm_identity() -> meerkat_core::SessionLlmIdentity {
    meerkat_core::SessionLlmIdentity {
        model: "claude-sonnet-4-5".to_string(),
        provider: meerkat_core::Provider::Anthropic,
        self_hosted_server_id: None,
        provider_params: None,
        auth_binding: None,
    }
}

/// THE resume-strand class test (0.7.19–0.7.23, field: "guard rejected
/// transition from phase Stopped for input::PublishLocalEndpoint"): the
/// machine owns revival of a stopped session at the canonical resume seam.
///
/// 1. Build inputs fired directly against a Stopped machine guard-reject
///    loudly — the per-input Stopped-tolerance arms are gone.
/// 2. `prepare_bindings` (which stages `RegisterSession` unconditionally)
///    revives the session via `RegisterSessionResumesStopped`, so the
///    resume build — hydration AND the peer-comms install that produced
///    the field failure — runs against a live phase.
#[tokio::test]
async fn stopped_session_resume_class_revives_at_the_canonical_seam() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    let bindings = adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect("prepare bindings registers the session");

    adapter
        .stop_runtime_executor(&session_id, "host shutdown")
        .await
        .expect("stop should succeed");
    let stopped = adapter
        .meerkat_machine_spine_snapshot(&session_id)
        .await
        .expect("snapshot should exist after stop");
    assert_eq!(stopped.control.phase, RuntimeState::Stopped);

    // 1. No tolerance arms: build inputs at Stopped are loud ordering bugs.
    let rejected = bindings
        .model_routing()
        .hydrate_llm_capability_surface(&test_llm_identity(), None, &meerkat_core::ToolFilter::All)
        .expect_err("hydration against a Stopped machine must guard-reject, not silently no-op");
    assert!(
        rejected.to_string().contains("Stopped"),
        "rejection must name the Stopped phase: {rejected}"
    );
    let target = AcceptingPeerCommsInstallTarget::new("resume-target", 7);
    let install_rejected = bindings
        .install_peer_comms_on(&target)
        .expect_err("peer-comms install against a Stopped machine must fail closed");
    assert!(
        install_rejected.contains("Stopped"),
        "install rejection must name the Stopped phase: {install_rejected}"
    );

    // 2. The canonical resume seam revives the session; the resume build
    //    then succeeds end to end, including the exact field-failure input.
    let resumed = adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect("resume prepare_bindings must revive the stopped session");
    let revived = adapter
        .meerkat_machine_spine_snapshot(&session_id)
        .await
        .expect("snapshot should exist after revival");
    assert_ne!(
        revived.control.phase,
        RuntimeState::Stopped,
        "revival must leave the visible runtime phase live"
    );
    resumed
        .model_routing()
        .hydrate_llm_capability_surface(&test_llm_identity(), None, &meerkat_core::ToolFilter::All)
        .expect("resume build hydration succeeds post-revival");
    resumed
        .install_peer_comms_on(&target)
        .expect("peer-comms install (PublishLocalEndpoint) succeeds post-revival");
}

/// Race pin: a stop landing AFTER revival re-enters Stopped, and a
/// subsequent build input fails closed with the same historical error
/// signature. This is correct behavior — the pin exists so a future field
/// recurrence of the string is distinguishable from a revival regression
/// (the resume seam itself is covered by the test above).
#[tokio::test]
async fn stop_after_revival_fails_the_next_build_input_closed() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect("prepare bindings registers the session");
    adapter
        .stop_runtime_executor(&session_id, "host shutdown")
        .await
        .expect("stop should succeed");
    let resumed = adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect("resume prepare_bindings must revive the stopped session");
    adapter
        .stop_runtime_executor(&session_id, "raced stop")
        .await
        .expect("second stop should succeed");
    let target = AcceptingPeerCommsInstallTarget::new("raced-target", 9);
    let error = resumed
        .install_peer_comms_on(&target)
        .expect_err("install racing a stop must fail closed");
    assert!(
        error.contains("guard rejected transition from phase Stopped")
            && error.contains("PublishLocalEndpoint"),
        "raced install must surface the typed Stopped rejection: {error}"
    );
}

/// Disposal-of-stopped class (the ask-21d strand): retiring a registered
/// session whose machine is Stopped is a machine transition (`Retire`
/// admits Stopped) that lands in Retired — not a silent shell early-return
/// that strands the session un-retired.
#[tokio::test]
async fn stopped_session_retire_completes_durably() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect("prepare bindings registers the session");
    adapter
        .stop_runtime_executor(&session_id, "host shutdown")
        .await
        .expect("stop should succeed");
    let runtime_id = crate::identifiers::LogicalRuntimeId::for_session(&session_id);
    crate::traits::RuntimeControlPlane::retire(adapter.as_ref(), &runtime_id)
        .await
        .expect("retire of a stopped session must be a machine transition");
    let retired = adapter
        .meerkat_machine_spine_snapshot(&session_id)
        .await
        .expect("snapshot should exist after retire");
    assert_eq!(
        retired.control.phase,
        RuntimeState::Retired,
        "retire from Stopped must land in Retired"
    );
}

/// Cold-revival class (the 0.7.25 identity-first field wedge): a process
/// dies with a session durably Stopped AND still carrying its runtime
/// binding (no unregister ran — the torn case). A fresh machine over the
/// same store recovers that state, revival re-admits the session, and the
/// new registration epoch's `PrepareBindings` MUST bind. Pre-fix the
/// revival preserved the dead epoch's tuple and every re-bind was
/// guard-rejected ("DSL rejected PrepareBindings: GuardRejected"),
/// laundered upstream into "session not found in runtime adapter after
/// registration".
#[cfg(not(target_arch = "wasm32"))]
#[tokio::test]
async fn cold_revival_rebinds_after_torn_shutdown_with_bound_stopped_state() {
    let store =
        Arc::new(crate::store::InMemoryRuntimeStore::new()) as Arc<dyn crate::store::RuntimeStore>;
    let session_id = SessionId::new();

    let first = MeerkatMachine::persistent(Arc::clone(&store), memory_blob_store());
    first
        .prepare_bindings(session_id.clone())
        .await
        .expect("first-epoch prepare_bindings registers and binds");
    first
        .stop_runtime_executor(&session_id, "host shutdown")
        .await
        .expect("stop should succeed");
    // Torn shutdown: the process dies here — no unregister ever runs, so the
    // durable row keeps phase Stopped with the first epoch's binding tuple.
    drop(first);

    let restarted = MeerkatMachine::persistent(store, memory_blob_store());
    let resumed = restarted.prepare_bindings(session_id.clone()).await.expect(
        "cold-revival prepare_bindings must revive AND re-bind the session under \
             the fresh registration epoch — a rejected re-bind is the field wedge",
    );
    let revived = restarted
        .meerkat_machine_spine_snapshot(&session_id)
        .await
        .expect("snapshot should exist after cold revival");
    assert_ne!(
        revived.control.phase,
        RuntimeState::Stopped,
        "cold revival must leave the visible runtime phase live"
    );
    resumed
        .model_routing()
        .hydrate_llm_capability_surface(&test_llm_identity(), None, &meerkat_core::ToolFilter::All)
        .expect("resume build hydration succeeds after cold revival");
}

/// A completed durable unregister is a terminalized old epoch, not a
/// resumable drain prefix. A later binding preparation must therefore start a
/// fresh runtime epoch instead of recovering `Stopped + Draining`.
#[cfg(not(target_arch = "wasm32"))]
#[tokio::test]
async fn durable_unregister_then_prepare_bindings_starts_fresh_epoch() {
    let store =
        Arc::new(crate::store::InMemoryRuntimeStore::new()) as Arc<dyn crate::store::RuntimeStore>;
    let session_id = SessionId::new();
    let adapter = MeerkatMachine::persistent(store, memory_blob_store());

    adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect("first epoch binds");
    adapter
        .unregister_session(&session_id)
        .await
        .expect("first epoch unregisters durably");
    assert!(!adapter.contains_session(&session_id).await);

    adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect("completed unregister must admit a fresh runtime epoch");
    assert!(adapter.contains_session(&session_id).await);
}

/// Machine-level revival semantics: the revival arms preserve session
/// identity and hydrated LLM/capability state while clearing the
/// epoch-scoped runtime binding tuple (Stopped proves the bound epoch's
/// executor exited; the next `PrepareBindings` binds the new epoch), and
/// both revival arms refuse while an unregister drain window is open.
#[test]
fn revival_arms_preserve_identity_clear_epoch_binding_and_refuse_while_draining() {
    use crate::meerkat_machine::dsl as mm_dsl;

    let stopped_state = || mm_dsl::MeerkatMachineState {
        lifecycle_phase: mm_dsl::MeerkatPhase::Stopped,
        session_id: Some(mm_dsl::SessionId("session-revive".to_string())),
        active_runtime_id: Some(mm_dsl::AgentRuntimeId("runtime-1".to_string())),
        active_fence_token: Some(mm_dsl::FenceToken(3)),
        active_runtime_epoch_id: Some(mm_dsl::RuntimeEpochId("epoch-1".to_string())),
        ..Default::default()
    };
    let assert_epoch_binding_cleared = |state: &mm_dsl::MeerkatMachineState, arc: &str| {
        assert_eq!(
            state.active_runtime_id, None,
            "{arc}: the runtime binding is epoch-scoped; Stopped proves the bound \
             epoch's executor exited, so revival must clear it (a preserved dead \
             binding makes every PrepareBindings re-bind guard-rejected — the \
             0.7.25 identity-first cold-revival wedge)"
        );
        assert_eq!(state.active_fence_token, None, "{arc}: fence cleared");
        assert_eq!(
            state.active_runtime_generation, None,
            "{arc}: generation cleared"
        );
        assert_eq!(
            state.active_runtime_epoch_id, None,
            "{arc}: epoch id cleared"
        );
    };
    // The new epoch's binding, as the shell/mob presents it after revival —
    // deliberately different from the dead epoch's tuple in every field.
    let rebind_input = || mm_dsl::MeerkatMachineInput::PrepareBindings {
        agent_runtime_id: mm_dsl::AgentRuntimeId("runtime-2".to_string()),
        fence_token: mm_dsl::FenceToken(4),
        generation: None,
        runtime_epoch_id: Some(mm_dsl::RuntimeEpochId("epoch-2".to_string())),
        session_id: mm_dsl::SessionId("session-revive".to_string()),
    };

    // RegisterSession revival: Stopped → Idle preserving identity, clearing
    // the dead epoch's binding tuple; the new epoch then binds cleanly.
    let mut authority = mm_dsl::MeerkatMachineAuthority::recover_from_state(stopped_state())
        .expect("stopped state must be recoverable");
    mm_dsl::MeerkatMachineMutator::apply(
        &mut authority,
        mm_dsl::MeerkatMachineInput::RegisterSession {
            session_id: mm_dsl::SessionId("session-revive".to_string()),
        },
    )
    .expect("same-session re-registration must revive a stopped machine");
    assert_eq!(
        authority.state().lifecycle_phase,
        mm_dsl::MeerkatPhase::Idle
    );
    assert_eq!(
        authority.state().session_id,
        Some(mm_dsl::SessionId("session-revive".to_string())),
        "revival must preserve the session identity"
    );
    assert_epoch_binding_cleared(authority.state(), "RegisterSession revival");
    mm_dsl::MeerkatMachineMutator::apply(&mut authority, rebind_input()).expect(
        "the fresh epoch's PrepareBindings must bind a revived session — a \
         rejected re-bind is the cold-revival wedge class",
    );
    assert_eq!(
        authority.state().active_runtime_epoch_id,
        Some(mm_dsl::RuntimeEpochId("epoch-2".to_string())),
        "re-bind must adopt the new epoch's tuple"
    );

    // EnsureSessionWithExecutor revival: Stopped → Attached + Active, with
    // the same epoch-binding clear; the re-bind is admissible AT ATTACHED —
    // the exact field rejection signature (PrepareBindings GuardRejected
    // { phase: Attached }).
    let mut authority = mm_dsl::MeerkatMachineAuthority::recover_from_state(stopped_state())
        .expect("stopped state must be recoverable");
    mm_dsl::MeerkatMachineMutator::apply(
        &mut authority,
        mm_dsl::MeerkatMachineInput::EnsureSessionWithExecutor {
            session_id: mm_dsl::SessionId("session-revive".to_string()),
        },
    )
    .expect("ensure-with-executor must revive a stopped machine");
    assert_eq!(
        authority.state().lifecycle_phase,
        mm_dsl::MeerkatPhase::Attached
    );
    assert_eq!(
        authority.state().registration_phase,
        mm_dsl::RegistrationPhase::Active,
        "executor revival must grant the active registration claim"
    );
    assert_epoch_binding_cleared(authority.state(), "EnsureSessionWithExecutor revival");
    mm_dsl::MeerkatMachineMutator::apply(&mut authority, rebind_input()).expect(
        "the fresh epoch's PrepareBindings must bind at Attached after executor \
         revival — the exact field rejection this class test kills",
    );
    assert_eq!(
        authority.state().lifecycle_phase,
        mm_dsl::MeerkatPhase::Attached,
        "re-bind at Attached self-loops"
    );

    // Both revivals refuse while the unregister drain window is open: the
    // drain completes (UnregisterSessionStopped) before any resume.
    let draining_state = || {
        let mut state = stopped_state();
        state.registration_phase = mm_dsl::RegistrationPhase::Draining;
        state
    };
    let mut authority = mm_dsl::MeerkatMachineAuthority::recover_from_state(draining_state())
        .expect("draining state must be recoverable");
    mm_dsl::MeerkatMachineMutator::apply(
        &mut authority,
        mm_dsl::MeerkatMachineInput::RegisterSession {
            session_id: mm_dsl::SessionId("session-revive".to_string()),
        },
    )
    .expect_err("revival must refuse while the unregister drain window is open");
    assert_eq!(
        authority.state().lifecycle_phase,
        mm_dsl::MeerkatPhase::Stopped,
        "refused revival must not change the phase"
    );
    let mut authority = mm_dsl::MeerkatMachineAuthority::recover_from_state(draining_state())
        .expect("draining state must be recoverable");
    mm_dsl::MeerkatMachineMutator::apply(
        &mut authority,
        mm_dsl::MeerkatMachineInput::EnsureSessionWithExecutor {
            session_id: mm_dsl::SessionId("session-revive".to_string()),
        },
    )
    .expect_err("executor revival must refuse while the unregister drain window is open");
}

/// `Queuing` is only the recovered registration default; it is not evidence
/// that an exact authoritative binding is stale. Standard (non-Mob) recovery
/// may reassert that tuple before attaching its executor, and generic ensure
/// must preserve it.
#[test]
fn recovered_idle_exact_binding_survives_authoritative_prepare_then_executor_attach() {
    use crate::meerkat_machine::dsl as mm_dsl;

    let session_id = mm_dsl::SessionId("session-idle-current-binding".to_string());
    let runtime_id = mm_dsl::AgentRuntimeId("runtime-current".to_string());
    let fence = mm_dsl::FenceToken(51);
    let generation = mm_dsl::Generation(9);
    let epoch = mm_dsl::RuntimeEpochId("epoch-current".to_string());
    let mut authority =
        mm_dsl::MeerkatMachineAuthority::recover_from_state(mm_dsl::MeerkatMachineState {
            lifecycle_phase: mm_dsl::MeerkatPhase::Idle,
            session_id: Some(session_id.clone()),
            registration_phase: mm_dsl::RegistrationPhase::Queuing,
            active_runtime_id: Some(runtime_id.clone()),
            active_fence_token: Some(fence),
            active_runtime_generation: Some(generation),
            active_runtime_epoch_id: Some(epoch.clone()),
            ..Default::default()
        })
        .expect("an idle recovered runtime with an exact binding must be valid");

    mm_dsl::MeerkatMachineMutator::apply(
        &mut authority,
        mm_dsl::MeerkatMachineInput::PrepareBindings {
            agent_runtime_id: runtime_id.clone(),
            fence_token: fence,
            generation: Some(generation),
            runtime_epoch_id: Some(epoch.clone()),
            session_id: session_id.clone(),
        },
    )
    .expect("exact authoritative binding reassertion must be idempotent");
    mm_dsl::MeerkatMachineMutator::apply(
        &mut authority,
        mm_dsl::MeerkatMachineInput::EnsureSessionWithExecutor { session_id },
    )
    .expect("standard recovered runtime must attach its executor");

    let attached = authority.state();
    assert_eq!(attached.lifecycle_phase, mm_dsl::MeerkatPhase::Attached);
    assert_eq!(
        attached.registration_phase,
        mm_dsl::RegistrationPhase::Active
    );
    assert_eq!(attached.active_runtime_id, Some(runtime_id));
    assert_eq!(attached.active_fence_token, Some(fence));
    assert_eq!(attached.active_runtime_generation, Some(generation));
    assert_eq!(attached.active_runtime_epoch_id, Some(epoch));
}

#[tokio::test]
async fn model_routing_status_proves_finite_turn_and_operation_precedence() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    <MeerkatMachine as SessionServiceRuntimeExt>::configure_model_routing_baseline(
        &adapter,
        &session_id,
        model("baseline"),
        true,
    )
    .await
    .expect("baseline should be projected through machine command surface");

    let switch = finite_switch_request(
        101,
        "turn-target",
        meerkat_core::image_generation::FiniteScopedTurnDuration::OneTurn,
    );
    <MeerkatMachine as SessionServiceRuntimeExt>::request_switch_turn(
        &adapter,
        &session_id,
        switch,
    )
    .await
    .expect("finite switch_turn should be admitted");

    let before_boundary =
        <MeerkatMachine as SessionServiceRuntimeExt>::session_model_routing_status(
            &adapter,
            &session_id,
        )
        .await
        .expect("status should project");
    assert_eq!(before_boundary.effective_model.as_str(), "baseline");
    assert!(
        before_boundary.pending_switch_turn.is_some(),
        "finite switch_turn waits for the next admitted assistant-turn boundary"
    );

    <MeerkatMachine as SessionServiceRuntimeExt>::admit_model_routing_assistant_turn(
        &adapter,
        &session_id,
    )
    .await
    .expect("assistant-turn boundary should activate finite override");
    let turn_active = <MeerkatMachine as SessionServiceRuntimeExt>::session_model_routing_status(
        &adapter,
        &session_id,
    )
    .await
    .expect("status should project");
    assert_eq!(turn_active.effective_model.as_str(), "turn-target");

    let image = image_request(201, "operation-target");
    let operation_id = image.operation_id;
    let image_result = <MeerkatMachine as SessionServiceRuntimeExt>::begin_image_operation(
        &adapter,
        &session_id,
        image,
    )
    .await
    .expect("image operation should be admitted under turn override");
    assert!(matches!(
        image_result,
        ImageOperationRoutingResult::Accepted {
            phase: meerkat_core::image_generation::ImageOperationPhase::PlanResolved,
            ..
        }
    ));
    <MeerkatMachine as SessionServiceRuntimeExt>::activate_image_operation_override(
        &adapter,
        &session_id,
        operation_id,
    )
    .await
    .expect("operation-scoped override should activate");
    let operation_active =
        <MeerkatMachine as SessionServiceRuntimeExt>::session_model_routing_status(
            &adapter,
            &session_id,
        )
        .await
        .expect("status should project");
    assert_eq!(
        operation_active.effective_model.as_str(),
        "operation-target",
        "operation override takes precedence over the active turn override"
    );

    let provider_text = meerkat_core::image_generation::ProviderTextDisposition::Captured {
        text_artifact_ref: meerkat_core::image_generation::TextArtifactRef::new(
            "provider-text-artifact",
        ),
    };
    let empty_terminal =
        <MeerkatMachine as SessionServiceRuntimeExt>::classify_image_operation_terminal(
            &adapter,
            &session_id,
            operation_id,
            meerkat_core::image_generation::ImageProviderTerminalObservation::EmptyResult,
            provider_text,
        )
        .await
        .expect("image terminal should classify through machine authority");
    assert!(matches!(
        empty_terminal,
        meerkat_core::image_generation::ImageOperationTerminalClass::EmptyResult { .. }
    ));
    <MeerkatMachine as SessionServiceRuntimeExt>::complete_image_operation(
        &adapter,
        &session_id,
        operation_id,
        empty_terminal.clone(),
    )
    .await
    .expect("image operation should enter restore phase");
    let restored_phase =
        <MeerkatMachine as SessionServiceRuntimeExt>::restore_image_operation_override(
            &adapter,
            &session_id,
            operation_id,
        )
        .await
        .expect("operation restore should clear child override");
    assert_eq!(
        restored_phase,
        meerkat_core::image_generation::ImageOperationPhase::Terminal {
            terminal: empty_terminal
        },
        "restore should preserve the exact payload-bearing terminal passed to complete"
    );
    let restored_to_turn =
        <MeerkatMachine as SessionServiceRuntimeExt>::session_model_routing_status(
            &adapter,
            &session_id,
        )
        .await
        .expect("status should project");
    assert_eq!(restored_to_turn.effective_model.as_str(), "turn-target");

    <MeerkatMachine as SessionServiceRuntimeExt>::admit_model_routing_assistant_turn(
        &adapter,
        &session_id,
    )
    .await
    .expect("next admitted assistant turn should consume one-turn override");
    let consumed = <MeerkatMachine as SessionServiceRuntimeExt>::session_model_routing_status(
        &adapter,
        &session_id,
    )
    .await
    .expect("status should project");
    assert_eq!(consumed.effective_model.as_str(), "baseline");
    assert!(consumed.active_turn_override.is_none());
}

#[tokio::test]
async fn model_routing_denials_cover_approval_and_scoped_nesting_guards() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");
    <MeerkatMachine as SessionServiceRuntimeExt>::configure_model_routing_baseline(
        &adapter,
        &session_id,
        model("baseline"),
        true,
    )
    .await
    .unwrap();

    let mut denied_switch = finite_switch_request(
        301,
        "expensive-target",
        meerkat_core::image_generation::FiniteScopedTurnDuration::OneTurn,
    );
    denied_switch.approval = ModelRoutingApprovalDisposition::DeniedByUser;
    denied_switch.approval_reason =
        Some(meerkat_core::image_generation::SwitchTurnApprovalReason::CostExceedsThreshold);
    let denied = <MeerkatMachine as SessionServiceRuntimeExt>::request_switch_turn(
        &adapter,
        &session_id,
        denied_switch,
    )
    .await
    .expect("denial should terminalize through machine state");
    assert!(matches!(
        denied,
        meerkat_core::image_generation::SwitchTurnControlResult::Denied {
            reason: meerkat_core::image_generation::SwitchTurnDenialReason::DeniedDuringApproval {
                approvable:
                    meerkat_core::image_generation::SwitchTurnApprovalReason::CostExceedsThreshold
            },
            ..
        }
    ));

    let mut denied_until_changed = SwitchTurnRequest {
        request_id: meerkat_core::image_generation::SwitchTurnRequestId::new(uuid(304)),
        intent: meerkat_core::image_generation::SwitchTurnIntent {
            target_model: model("persistent-denied-target"),
            duration: meerkat_core::image_generation::SwitchTurnDuration::UntilChanged,
            origin: meerkat_core::image_generation::SwitchTurnOrigin::SystemPolicy {
                reason: meerkat_core::image_generation::SwitchTurnPolicyReason::SafetyHandoff,
            },
        },
        target_realtime: realtime_policy(true),
        approval: ModelRoutingApprovalDisposition::RequiredButUnavailable,
        approval_reason: Some(
            meerkat_core::image_generation::SwitchTurnApprovalReason::UntilChangedFromModelOrigin,
        ),
    };
    let denied_persistent = <MeerkatMachine as SessionServiceRuntimeExt>::request_switch_turn(
        &adapter,
        &session_id,
        denied_until_changed.clone(),
    )
    .await
    .expect("UntilChanged approval-unavailable denial should terminalize");
    assert!(matches!(
        denied_persistent,
        meerkat_core::image_generation::SwitchTurnControlResult::Denied {
            reason:
                meerkat_core::image_generation::SwitchTurnDenialReason::ApprovalRequiredButUnavailable,
            ..
        }
    ));
    denied_until_changed.request_id =
        meerkat_core::image_generation::SwitchTurnRequestId::new(uuid(305));
    denied_until_changed.approval = ModelRoutingApprovalDisposition::DeniedByUser;
    let denied_by_user = <MeerkatMachine as SessionServiceRuntimeExt>::request_switch_turn(
        &adapter,
        &session_id,
        denied_until_changed,
    )
    .await
    .expect("UntilChanged user denial should terminalize");
    assert!(matches!(
        denied_by_user,
        meerkat_core::image_generation::SwitchTurnControlResult::Denied {
            reason: meerkat_core::image_generation::SwitchTurnDenialReason::DeniedDuringApproval {
                approvable: meerkat_core::image_generation::SwitchTurnApprovalReason::UntilChangedFromModelOrigin
            },
            ..
        }
    ));

    let mut denied_image = image_request(400, "image-denied-target");
    denied_image.approval = ModelRoutingApprovalDisposition::DeniedByUser;
    denied_image.approval_reason =
        Some(meerkat_core::image_generation::ImageOperationApprovalReason::SafetyHold);
    let denied_image_result = <MeerkatMachine as SessionServiceRuntimeExt>::begin_image_operation(
        &adapter,
        &session_id,
        denied_image,
    )
    .await
    .expect("image user denial should terminalize");
    assert!(matches!(
        denied_image_result,
        ImageOperationRoutingResult::Denied {
            reason:
                meerkat_core::image_generation::ImageOperationDenialReason::DeniedDuringApproval {
                    approvable:
                        meerkat_core::image_generation::ImageOperationApprovalReason::SafetyHold
                },
            ..
        }
    ));

    let active_switch = finite_switch_request(
        302,
        "turn-target",
        meerkat_core::image_generation::FiniteScopedTurnDuration::Turns {
            turns: NonZeroU32::new(2).unwrap(),
        },
    );
    <MeerkatMachine as SessionServiceRuntimeExt>::request_switch_turn(
        &adapter,
        &session_id,
        active_switch,
    )
    .await
    .unwrap();
    <MeerkatMachine as SessionServiceRuntimeExt>::admit_model_routing_assistant_turn(
        &adapter,
        &session_id,
    )
    .await
    .unwrap();

    let nested_switch = finite_switch_request(
        303,
        "nested-turn-target",
        meerkat_core::image_generation::FiniteScopedTurnDuration::OneTurn,
    );
    let nested_switch_result = <MeerkatMachine as SessionServiceRuntimeExt>::request_switch_turn(
        &adapter,
        &session_id,
        nested_switch,
    )
    .await
    .expect("scoped conflict should return typed denial");
    assert!(matches!(
        nested_switch_result,
        meerkat_core::image_generation::SwitchTurnControlResult::Denied {
            reason: meerkat_core::image_generation::SwitchTurnDenialReason::ScopedOverrideConflict,
            ..
        }
    ));

    let image = image_request(401, "operation-target");
    let operation_id = image.operation_id;
    <MeerkatMachine as SessionServiceRuntimeExt>::begin_image_operation(
        &adapter,
        &session_id,
        image,
    )
    .await
    .unwrap();
    <MeerkatMachine as SessionServiceRuntimeExt>::activate_image_operation_override(
        &adapter,
        &session_id,
        operation_id,
    )
    .await
    .unwrap();

    let nested_image = image_request(402, "nested-operation-target");
    let nested_image_result = <MeerkatMachine as SessionServiceRuntimeExt>::begin_image_operation(
        &adapter,
        &session_id,
        nested_image,
    )
    .await
    .expect("operation-in-operation conflict should terminalize");
    assert!(matches!(
        nested_image_result,
        ImageOperationRoutingResult::Denied {
            reason:
                meerkat_core::image_generation::ImageOperationDenialReason::ScopedOverrideConflict,
            ..
        }
    ));
}

#[tokio::test]
async fn until_changed_switch_turn_reconfigures_baseline_not_scoped_override() {
    struct NoopExecutor;

    #[async_trait::async_trait]
    impl CoreExecutor for NoopExecutor {
        async fn apply(
            &mut self,
            run_id: RunId,
            primitive: RunPrimitive,
        ) -> Result<CoreApplyOutput, CoreExecutorError> {
            Ok(CoreApplyOutput {
                receipt: RunBoundaryReceiptDraft {
                    run_id,
                    boundary: RunApplyBoundary::RunStart,
                    contributing_input_ids: primitive.contributing_input_ids().to_vec(),
                    conversation_digest: None,
                    message_count: 0,
                },
                session_snapshot: None,
                terminal: None,
            })
        }

        async fn cancel_after_boundary(
            &mut self,
            _reason: String,
        ) -> Result<(), CoreExecutorError> {
            Ok(())
        }

        async fn stop_runtime_executor(
            &mut self,
            _reason: String,
        ) -> Result<(), CoreExecutorError> {
            Ok(())
        }
    }

    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .prepare_bindings(session_id.clone())
        .await
        .expect("bindings should prepare");
    adapter
        .ensure_session_with_executor(session_id.clone(), Box::new(NoopExecutor))
        .await
        .expect("runtime executor registration should succeed");
    let current_identity = Arc::new(std::sync::Mutex::new(meerkat_core::SessionLlmIdentity {
        model: "baseline".to_string(),
        provider: meerkat_core::Provider::OpenAI,
        self_hosted_server_id: None,
        provider_params: None,
        auth_binding: None,
    }));
    let current_visibility_state = Arc::new(std::sync::Mutex::new(
        meerkat_core::SessionToolVisibilityState::default(),
    ));
    adapter.set_session_llm_reconfigure_host(Arc::new(TestLlmReconfigureHost {
        current_identity: Arc::clone(&current_identity),
        current_visibility_state: Arc::clone(&current_visibility_state),
        target_identity: meerkat_core::SessionLlmIdentity {
            model: "persistent-target".to_string(),
            provider: meerkat_core::Provider::OpenAI,
            self_hosted_server_id: None,
            provider_params: None,
            auth_binding: None,
        },
        current_capability_surface: Some(test_llm_capability_surface(true)),
        target_capability_surface: test_llm_capability_surface(true),
        base_tool_names: BTreeSet::new(),
        fail_persist: false,
    }));
    <MeerkatMachine as SessionServiceRuntimeExt>::configure_model_routing_baseline(
        &adapter,
        &session_id,
        model("baseline"),
        true,
    )
    .await
    .unwrap();

    let request = SwitchTurnRequest {
        request_id: meerkat_core::image_generation::SwitchTurnRequestId::new(uuid(501)),
        intent: meerkat_core::image_generation::SwitchTurnIntent {
            target_model: model("persistent-target"),
            duration: meerkat_core::image_generation::SwitchTurnDuration::UntilChanged,
            origin: meerkat_core::image_generation::SwitchTurnOrigin::SystemPolicy {
                reason: meerkat_core::image_generation::SwitchTurnPolicyReason::SafetyHandoff,
            },
        },
        target_realtime: realtime_policy(true),
        approval: ModelRoutingApprovalDisposition::NotRequired,
        approval_reason: None,
    };
    <MeerkatMachine as SessionServiceRuntimeExt>::request_switch_turn(
        &adapter,
        &session_id,
        request,
    )
    .await
    .expect("UntilChanged should route through persistent reconfigure family");

    let status = <MeerkatMachine as SessionServiceRuntimeExt>::session_model_routing_status(
        &adapter,
        &session_id,
    )
    .await
    .unwrap();
    assert_eq!(status.baseline_model.as_str(), "persistent-target");
    assert_eq!(status.effective_model.as_str(), "persistent-target");
    assert!(status.active_turn_override.is_none());
    assert_eq!(
        current_identity
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner)
            .model,
        "persistent-target",
        "UntilChanged switch_turn must pass through the live LLM reconfigure host"
    );
}

#[tokio::test]
async fn meerkat_machine_spine_snapshot_reports_registered_idle_session() {
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();

    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");

    let snapshot = adapter
        .meerkat_machine_spine_snapshot(&session_id)
        .await
        .expect("snapshot should exist for registered session");

    assert_eq!(snapshot.binding.session_id, session_id);
    assert_eq!(
        snapshot.binding.driver_kind,
        crate::meerkat_machine_types::MeerkatDriverKind::Ephemeral
    );
    assert!(snapshot.binding.driver_present);
    assert!(snapshot.binding.completions_present);
    assert!(snapshot.binding.ops_registry_present);
    assert_eq!(snapshot.control.phase, RuntimeState::Idle);
    assert_eq!(snapshot.binding.cursor_state.agent_applied_cursor, 0);
    assert_eq!(snapshot.binding.cursor_state.runtime_observed_seq, 0);
    assert_eq!(snapshot.binding.cursor_state.runtime_last_injected_seq, 0);
    assert!(snapshot.inputs.admission_order.is_empty());
    assert!(snapshot.inputs.queue.is_empty());
    assert!(snapshot.inputs.steer_queue.is_empty());
    assert_eq!(snapshot.completion_waiters.input_count, 0);
    assert_eq!(snapshot.completion_waiters.waiter_count, 0);
    assert!(snapshot.completion_waiters.waiting_inputs.is_empty());
    assert!(!snapshot.drain.slot_present);
    assert_eq!(snapshot.drain.phase, None);
    assert_eq!(snapshot.drain.mode, None);
    assert!(!snapshot.drain.handle_present);
}

