async fn assert_recovered_rotation_phase(
    machine: &MeerkatMachine,
    session_id: &SessionId,
    expected: dsl::SupervisorRotationPhase,
) {
    let receipt = machine
        .active_supervisor_rotation(session_id)
        .await
        .expect("read recovered rotation")
        .expect("recovered rotation receipt");
    assert_eq!(receipt.phase, expected);
}

#[tokio::test]
async fn supervisor_rotation_persistence_failures_leave_cold_resumable_checkpoints() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let fault_store = Arc::new(RuntimeCommitAtomicityStore::pass_through(inner));
    let store: Arc<dyn RuntimeStore> = fault_store.clone();
    let session_id = SessionId::new();
    let previous_peer_id = meerkat_core::comms::PeerId::from_ed25519_pubkey(&[0xbb; 32]).as_str();
    let next_peer_id = meerkat_core::comms::PeerId::from_ed25519_pubkey(&[0xdd; 32]).as_str();
    let previous_signing_key = crate::comms_drain::encode_supervisor_signing_public_key([0xbb; 32]);
    let next_signing_key = crate::comms_drain::encode_supervisor_signing_public_key([0xdd; 32]);
    let operation_id = uuid::Uuid::new_v4().to_string();

    let mut machine = MeerkatMachine::persistent_without_blobs(Arc::clone(&store));
    machine
        .register_session(session_id.clone())
        .await
        .expect("register persistent supervisor rotation");
    let endpoint_runtime: Arc<dyn CommsRuntime> = Arc::new(RotationEndpointRuntime {
        notify: Arc::new(Notify::new()),
    });
    machine
        .stage_local_endpoint_for_comms_runtime(&session_id, endpoint_runtime.as_ref())
        .await
        .expect("stage rotation local endpoint");
    machine
        .stage_supervisor_bind(
            &session_id,
            "previous-supervisor".to_string(),
            previous_peer_id.clone(),
            "inproc://previous-supervisor".to_string(),
            previous_signing_key.clone(),
            1,
        )
        .await
        .expect("stage previous supervisor");
    machine
        .stage_supervisor_trust_published(&session_id, previous_peer_id.clone(), 1)
        .await
        .expect("persist previous supervisor binding");

    fault_store
        .fail_commit_machine_lifecycle
        .store(true, Ordering::SeqCst);
    assert!(matches!(
        machine
            .submit_supervisor_rotation(
                &session_id,
                GeneratedSupervisorRotationSubmit {
                    operation_id: operation_id.clone(),
                    next: GeneratedSupervisorBinding {
                        name: "next-supervisor".to_string(),
                        peer_id: next_peer_id.clone(),
                        address: "inproc://next-supervisor".to_string(),
                        signing_public_key: next_signing_key.clone(),
                        epoch: 2,
                    },
                    preflight_rejection: None,
                    sender_peer_id: Some(previous_peer_id.clone()),
                    sender_signing_public_key: Some(previous_signing_key.clone()),
                },
            )
            .await,
        Err(SupervisorBindingStageError::Persistence(_))
    ));
    assert!(matches!(
        machine.supervisor_binding(&session_id).await,
        SupervisorBinding::Bound { ref peer_id, epoch: 1, .. } if peer_id == &previous_peer_id
    ));

    machine
        .submit_supervisor_rotation(
            &session_id,
            GeneratedSupervisorRotationSubmit {
                operation_id: operation_id.clone(),
                next: GeneratedSupervisorBinding {
                    name: "next-supervisor".to_string(),
                    peer_id: next_peer_id.clone(),
                    address: "inproc://next-supervisor".to_string(),
                    signing_public_key: next_signing_key.clone(),
                    epoch: 2,
                },
                preflight_rejection: None,
                sender_peer_id: Some(previous_peer_id.clone()),
                sender_signing_public_key: Some(previous_signing_key.clone()),
            },
        )
        .await
        .expect("persist previous-revoke checkpoint");
    fault_store
        .fail_commit_machine_lifecycle
        .store(true, Ordering::SeqCst);
    assert!(matches!(
        machine
            .stage_supervisor_rotation_previous_revoked(
                &session_id,
                operation_id.clone(),
                previous_peer_id.clone(),
                1,
            )
            .await,
        Err(SupervisorBindingStageError::Persistence(_))
    ));
    drop(machine);

    machine = MeerkatMachine::persistent_without_blobs(Arc::clone(&store));
    machine
        .register_session(session_id.clone())
        .await
        .expect("recover previous-revoke checkpoint");
    assert_recovered_rotation_phase(
        &machine,
        &session_id,
        dsl::SupervisorRotationPhase::PreviousRevokePending,
    )
    .await;
    machine
        .stage_supervisor_rotation_previous_revoked(
            &session_id,
            operation_id.clone(),
            previous_peer_id.clone(),
            1,
        )
        .await
        .expect("persist next-publish checkpoint");
    fault_store
        .fail_commit_machine_lifecycle
        .store(true, Ordering::SeqCst);
    assert!(matches!(
        machine
            .stage_supervisor_rotation_next_published(
                &session_id,
                operation_id.clone(),
                next_peer_id.clone(),
                2,
            )
            .await,
        Err(SupervisorBindingStageError::Persistence(_))
    ));
    drop(machine);

    machine = MeerkatMachine::persistent_without_blobs(Arc::clone(&store));
    machine
        .register_session(session_id.clone())
        .await
        .expect("recover next-publish checkpoint");
    assert_recovered_rotation_phase(
        &machine,
        &session_id,
        dsl::SupervisorRotationPhase::NextPublishPending,
    )
    .await;
    machine
        .stage_supervisor_rotation_next_published(&session_id, operation_id, next_peer_id, 2)
        .await
        .expect("persist completed rotation receipt");
    drop(machine);

    let recovered = MeerkatMachine::persistent_without_blobs(store);
    recovered
        .register_session(session_id.clone())
        .await
        .expect("recover completed rotation receipt");
    assert_recovered_rotation_phase(
        &recovered,
        &session_id,
        dsl::SupervisorRotationPhase::Completed,
    )
    .await;
}

async fn persistent_staged_run_driver(
    store: Arc<dyn RuntimeStore>,
) -> (SharedDriver, LogicalRuntimeId, RunId, InputId) {
    let runtime_id = LogicalRuntimeId::new("persistent-commit-atomicity");
    let mut driver = PersistentRuntimeDriver::new(runtime_id.clone(), store, memory_blob_store());
    let input = make_prompt("persistent terminalization");
    let input_id = input.id().clone();
    driver
        .accept_input(input)
        .await
        .expect("persistent input should be accepted");

    let run_id = RunId::new();
    driver
        .contract_begin_run_authority(run_id.clone())
        .expect("runtime run authority should begin through generated DSL");
    driver
        .machine_realize_authorized_stage_batch(
            crate::meerkat_machine::driver::test_authorized_stage_for_run(
                vec![input_id.clone()],
                run_id.clone(),
            ),
        )
        .expect("input should stage for the run");

    (
        Arc::new(Mutex::new(DriverEntry::Persistent(driver))),
        runtime_id,
        run_id,
        input_id,
    )
}

#[tokio::test]
async fn persistent_driver_recover_preserves_durable_runtime_authority() {
    let store = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let runtime_id = LogicalRuntimeId::new("persistent-recover-authority");
    crate::store::RuntimeStore::commit_machine_lifecycle(
        store.as_ref(),
        &runtime_id,
        crate::store::MachineLifecycleCommit::new_with_binding(
            RuntimeState::Retired,
            crate::store::MachineLifecycleBindingFacts::default(),
            crate::store::SupervisorAuthoritySnapshot::UnboundNoReceipt,
        ),
        &[],
    )
    .await
    .expect("seed retired runtime state");

    let mut driver = PersistentRuntimeDriver::new(
        runtime_id.clone(),
        store.clone() as Arc<dyn RuntimeStore>,
        memory_blob_store(),
    );
    driver
        .recover()
        .await
        .expect("public persistent recover should use generated runtime authority");

    assert_eq!(driver.runtime_state(), RuntimeState::Retired);
    assert_eq!(
        crate::store::load_runtime_state(store.as_ref(), &runtime_id)
            .await
            .expect("load runtime state after recovery"),
        Some(RuntimeState::Retired),
        "recovery must not rewrite durable lifecycle truth from the default shell"
    );

    let authority = driver.inner_ref().shared_dsl_authority();
    let authority = authority
        .lock()
        .unwrap_or_else(std::sync::PoisonError::into_inner);
    assert_eq!(
        authority.state().lifecycle_phase,
        mm_dsl::MeerkatPhase::Retired
    );
}

fn assert_live_run_remains_staged(
    entry: &DriverEntry,
    run_id: &RunId,
    input_id: &InputId,
    context: &str,
) {
    assert_eq!(
        entry.runtime_state(),
        RuntimeState::Running,
        "{context}: runtime must remain running"
    );
    assert_eq!(
        entry.current_run_id(),
        Some(run_id.clone()),
        "{context}: active run id must remain bound"
    );
    assert_eq!(
        entry.input_phase(input_id),
        Some(crate::input_state::InputLifecycleState::Staged),
        "{context}: contributor must remain staged"
    );
    assert_eq!(
        entry.input_terminal_outcome(input_id),
        None,
        "{context}: contributor must not be consumed or otherwise terminal"
    );

    let authority = entry.shared_dsl_authority();
    let auth = authority
        .lock()
        .unwrap_or_else(std::sync::PoisonError::into_inner);
    assert_eq!(
        auth.state().lifecycle_phase,
        mm_dsl::MeerkatPhase::Running,
        "{context}: DSL lifecycle must remain Running"
    );
    assert_eq!(
        auth.state().current_run_id.as_ref().map(|id| id.0.as_str()),
        Some(run_id.to_string().as_str()),
        "{context}: DSL current_run_id must remain bound"
    );
    assert_eq!(
        auth.state().turn_phase,
        mm_dsl::TurnPhase::Ready,
        "{context}: DSL turn_phase must not become terminal"
    );
    assert_eq!(
        auth.state().terminal_outcome,
        None,
        "{context}: DSL terminal_outcome must not be set"
    );
    assert_eq!(
        auth.state().input_phases.get(&input_id.to_string()),
        Some(&mm_dsl::InputPhase::Staged),
        "{context}: DSL input phase must remain staged"
    );
}

async fn assert_commit_rejection_preserved_staged_batch(
    driver: &SharedDriver,
    run_id: &RunId,
    staged_ids: &[InputId],
) {
    let entry = driver.lock().await;
    assert_eq!(
        entry.runtime_state(),
        RuntimeState::Running,
        "rejected commit must preserve the active run"
    );
    assert_eq!(
        entry.current_run_id(),
        Some(run_id.clone()),
        "rejected commit must preserve the active run id"
    );
    for input_id in staged_ids {
        assert_eq!(
            entry.input_phase(input_id),
            Some(crate::input_state::InputLifecycleState::Staged),
            "rejected commit must leave every contributor staged"
        );
    }
}

#[tokio::test]
async fn run_commit_rejects_receipt_run_id_mismatch_before_mutation() {
    let (driver, run_id, staged_ids) = staged_batch_commit_driver(
        make_queued_external_event("first"),
        make_queued_external_event("second"),
    )
    .await;

    let result = commit_runtime_loop_run(
        &driver,
        run_id.clone(),
        staged_ids.clone(),
        batch_receipt(RunId::new(), staged_ids.clone()),
        None,
    )
    .await;

    assert!(
        result.is_err(),
        "receipt for a different run id must reject before commit mutation"
    );
    assert_commit_rejection_preserved_staged_batch(&driver, &run_id, &staged_ids).await;
}

#[tokio::test]
async fn run_commit_rejects_reordered_receipt_contributors_before_mutation() {
    let (driver, run_id, staged_ids) = staged_batch_commit_driver(
        make_queued_external_event("first"),
        make_queued_external_event("second"),
    )
    .await;
    let mut receipt_contributors = staged_ids.clone();
    receipt_contributors.reverse();

    let result = commit_runtime_loop_run(
        &driver,
        run_id.clone(),
        staged_ids.clone(),
        batch_receipt(run_id.clone(), receipt_contributors),
        None,
    )
    .await;

    assert!(
        result.is_err(),
        "receipt contributors must exactly match consumed input ids"
    );
    assert_commit_rejection_preserved_staged_batch(&driver, &run_id, &staged_ids).await;
}

#[tokio::test]
async fn persistent_commit_atomic_apply_failure_preserves_pre_terminal_state() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store: Arc<dyn RuntimeStore> = Arc::new(
        RuntimeCommitAtomicityStore::fail_atomic_apply_once(Arc::clone(&inner)),
    );
    let (driver, runtime_id, run_id, input_id) = persistent_staged_run_driver(store).await;

    let err = commit_runtime_loop_run(
        &driver,
        run_id.clone(),
        vec![input_id.clone()],
        batch_receipt(run_id.clone(), vec![input_id.clone()]),
        Some(b"session-data".to_vec()),
    )
    .await
    .expect_err("synthetic atomic_apply failure should reject the commit");
    assert!(
        err.to_string().contains("synthetic atomic_apply failure"),
        "unexpected commit error: {err}"
    );

    let entry = driver.lock().await;
    assert_live_run_remains_staged(&entry, &run_id, &input_id, "failed boundary commit");
    drop(entry);

    assert!(
        inner
            .load_boundary_receipt(&runtime_id, &run_id, 0)
            .await
            .unwrap()
            .is_none(),
        "failed boundary commit must not persist a receipt"
    );
    assert_eq!(
        inner.load_session_snapshot(&runtime_id).await.unwrap(),
        None,
        "failed boundary commit must not persist a session snapshot"
    );
}

#[tokio::test]
async fn persistent_commit_success_persists_receipt_and_terminalizes_once() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store: Arc<dyn RuntimeStore> = inner.clone();
    let (driver, runtime_id, run_id, input_id) = persistent_staged_run_driver(store).await;
    let session_snapshot = serde_json::to_vec(&meerkat_core::Session::with_id(SessionId::new()))
        .expect("serialize session snapshot");

    commit_runtime_loop_run(
        &driver,
        run_id.clone(),
        vec![input_id.clone()],
        batch_receipt(run_id.clone(), vec![input_id.clone()]),
        Some(session_snapshot.clone()),
    )
    .await
    .expect("persistent commit should succeed");

    assert!(
        inner
            .load_boundary_receipt(&runtime_id, &run_id, 0)
            .await
            .unwrap()
            .is_some(),
        "successful commit must persist the boundary receipt"
    );
    assert_eq!(
        inner.load_session_snapshot(&runtime_id).await.unwrap(),
        Some(session_snapshot),
        "successful commit must persist the session snapshot"
    );

    // Dogma K10: the durable receipt's sequence is MINTED by the driver from
    // the machine-owned per-run boundary counter; executors return an
    // unsequenced draft and cannot fabricate it.
    let persisted_receipt = inner
        .load_boundary_receipt(&runtime_id, &run_id, 0)
        .await
        .unwrap()
        .expect("committed receipt must be durable");
    {
        let entry = driver.lock().await;
        assert_eq!(
            persisted_receipt.sequence,
            entry.run_boundary_sequence(&run_id),
            "durable receipt sequence must be the machine per-run boundary counter"
        );
    }

    let entry = driver.lock().await;
    assert_eq!(entry.runtime_state(), RuntimeState::Idle);
    assert_eq!(entry.current_run_id(), None);
    assert_eq!(
        entry.input_phase(&input_id),
        Some(crate::input_state::InputLifecycleState::Consumed)
    );
    assert_eq!(
        entry.input_terminal_outcome(&input_id),
        Some(crate::input_state::InputTerminalOutcome::Consumed)
    );
    let input_state = entry
        .as_driver()
        .input_state(&input_id)
        .expect("committed input state should remain available");
    assert_eq!(
        input_state
            .history
            .iter()
            .filter(|event| event.to == crate::input_state::InputLifecycleState::Consumed)
            .count(),
        1,
        "successful commit must consume the contributor exactly once"
    );

    let authority = entry.shared_dsl_authority();
    let auth = authority
        .lock()
        .unwrap_or_else(std::sync::PoisonError::into_inner);
    assert_eq!(auth.state().lifecycle_phase, mm_dsl::MeerkatPhase::Idle);
    assert_eq!(auth.state().current_run_id, None);
    assert_eq!(auth.state().turn_phase, mm_dsl::TurnPhase::Completed);
    assert_eq!(
        auth.state().terminal_outcome,
        Some(mm_dsl::TurnTerminalOutcome::Completed)
    );
    assert_eq!(
        auth.state().input_phases.get(&input_id.to_string()),
        Some(&mm_dsl::InputPhase::Consumed)
    );
}

#[tokio::test]
async fn persistent_commit_success_uses_one_durable_receipt_terminal_write() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let counting_store = Arc::new(RuntimeCommitAtomicityStore::pass_through(Arc::clone(
        &inner,
    )));
    let store: Arc<dyn RuntimeStore> = counting_store.clone();
    let (driver, runtime_id, run_id, input_id) = persistent_staged_run_driver(store).await;

    commit_runtime_loop_run(
        &driver,
        run_id.clone(),
        vec![input_id.clone()],
        batch_receipt(run_id.clone(), vec![input_id.clone()]),
        Some(
            serde_json::to_vec(&meerkat_core::Session::with_id(SessionId::new()))
                .expect("serialize session snapshot"),
        ),
    )
    .await
    .expect("persistent commit should succeed");

    assert_eq!(
        counting_store.commit_machine_lifecycle_calls(),
        0,
        "successful completed-run terminalization must not use a second lifecycle writer"
    );
    assert!(
        inner
            .load_boundary_receipt(&runtime_id, &run_id, 0)
            .await
            .unwrap()
            .is_some(),
        "successful commit must persist the durable boundary receipt"
    );
    let stored = inner
        .load_input_state(&runtime_id, &input_id)
        .await
        .unwrap()
        .expect("completed input state should be persisted with the receipt");
    assert_eq!(
        stored.seed.phase,
        crate::input_state::InputLifecycleState::Consumed,
        "receipt commit must persist the terminal input phase atomically"
    );
    assert_eq!(
        stored.seed.terminal_outcome,
        Some(crate::input_state::InputTerminalOutcome::Consumed),
        "receipt commit must persist the terminal input outcome atomically"
    );
}

#[tokio::test]
async fn persistent_failed_run_lifecycle_commit_failure_preserves_pre_terminal_state() {
    let inner = Arc::new(crate::store::InMemoryRuntimeStore::new());
    let store: Arc<dyn RuntimeStore> = Arc::new(
        RuntimeCommitAtomicityStore::fail_commit_machine_lifecycle_once(Arc::clone(&inner)),
    );
    let (driver, runtime_id, run_id, input_id) = persistent_staged_run_driver(store).await;

    let err = fail_runtime_loop_run(
        &driver,
        run_id.clone(),
        CoreApplyFailureCause::executor_internal("synthetic run failure"),
    )
    .await
    .expect_err("synthetic lifecycle commit failure should reject the failed-run persist");
    assert!(
        err.to_string()
            .contains("synthetic commit_machine_lifecycle failure"),
        "unexpected failed-run error: {err}"
    );

    let entry = driver.lock().await;
    assert_live_run_remains_staged(&entry, &run_id, &input_id, "failed run persist");
    drop(entry);

    assert_ne!(
        crate::store::load_runtime_state(inner.as_ref(), &runtime_id)
            .await
            .unwrap(),
        Some(RuntimeState::Idle),
        "failed run persist must not durably commit the returned runtime state"
    );
}

