#[tokio::test]
async fn detach_drops_drain_task_runtime_clone_so_identity_claim_is_released() {
    // Regression for the mob post-discard revival failure
    // "Session identity already active". The spawned comms-drain task captures
    // its own `Arc<dyn CommsRuntime>` clone, and a session-scoped inproc runtime
    // owns the process-scoped session-identity `SessionClaim`, released ONLY when
    // its LAST `Arc` is dropped. A fire-and-forget `handle.abort()` merely
    // schedules cancellation, so on a single-threaded runtime the task's clone is
    // still alive right after detach returns — and a same-id rebuild
    // (`materialize_revived_member_session` -> `provision_member`) then collides
    // with the still-held claim. The detach must JOIN the aborted drain task,
    // dropping its captured clone before returning. We observe that here through a
    // `Weak` handle: after detach, no strong `Arc` clone may survive.
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");

    let comms_runtime: Arc<dyn CommsRuntime> = Arc::new(FakeDrainRuntime::idle());
    let weak_runtime = Arc::downgrade(&comms_runtime);
    assert!(
        adapter
            .update_peer_ingress_context(&session_id, true, Some(Arc::clone(&comms_runtime)))
            .await
            .expect("attach session-owned drain"),
        "first session-owned attach should spawn the drain task"
    );

    // Drop the test's own strong reference so the only remaining strong holders
    // are the drain slot's `task_runtime` and the spawned drain task's captured
    // clone — exactly the state a live keep-alive session is in before revival.
    drop(comms_runtime);
    assert!(
        weak_runtime.upgrade().is_some(),
        "precondition: the drain slot + drain task must still hold the comms runtime"
    );

    adapter
        .update_peer_ingress_context(&session_id, false, None)
        .await
        .expect("detach drain");

    assert!(
        weak_runtime.upgrade().is_none(),
        "after detach, every Arc<dyn CommsRuntime> clone (slot + drain task) must be \
         dropped so the session-identity claim is released before any same-id rebuild; \
         a lingering clone is the race that surfaces as 'Session identity already active'"
    );
}

#[tokio::test]
async fn attach_mob_ingress_promotes_from_session_owned() {
    // Mob provisioning is allowed to take over a session-owned drain
    // (the spec's promotion case). Silent downgrade is blocked; promotion
    // is not.
    let adapter = Arc::new(MeerkatMachine::ephemeral());
    let session_id = SessionId::new();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");

    // Step 1: session attach.
    let session_comms: Arc<dyn CommsRuntime> = Arc::new(FakeDrainRuntime::idle());
    adapter
        .update_peer_ingress_context(&session_id, true, Some(Arc::clone(&session_comms)))
        .await
        .expect("update_peer_ingress_context");
    let carrier_dropped = install_test_rotation_carrier(
        &adapter,
        &session_id,
        Arc::clone(&session_comms),
        "promotion-carrier",
    )
    .await;

    // Step 2: mob provisioning promotes to MobOwned with (possibly) a
    // different comms runtime.
    let mob_comms: Arc<dyn CommsRuntime> = Arc::new(FakeDrainRuntime::idle());
    let mob_id = crate::meerkat_machine::dsl::MobId::from("mob-w2g-promotion");
    adapter
        .maybe_spawn_mob_comms_drain(&session_id, Arc::clone(&mob_comms), mob_id.clone())
        .await
        .expect("maybe_spawn_mob_comms_drain");

    let owner = adapter.peer_ingress_owner(&session_id).await;
    let expected_id = crate::meerkat_machine::dsl::CommsRuntimeId::from_runtime(&mob_comms);
    match owner {
        crate::meerkat_machine::PeerIngressOwner::MobOwned {
            comms_runtime_id,
            mob_id: actual_mob_id,
        } => {
            assert_eq!(comms_runtime_id, expected_id);
            assert_eq!(actual_mob_id, mob_id);
        }
        other => panic!("expected MobOwned after promotion, got {other:?}"),
    }
    assert!(
        carrier_dropped.load(Ordering::SeqCst),
        "SessionOwned -> MobOwned runtime change must quiesce the old rotation carrier"
    );
}

/// The transcript-edit session-liveness verdict is MeerkatMachine-owned: the
/// `SESSION_BUSY` disjunction (`runtime_running || has_active_inputs => busy`)
/// must be emitted from the two pure boolean observations the shell extracts.
/// This pins both outcomes through the machine-backed adapter, proving the fold
/// preserved the exact pre-fold shell policy.
#[tokio::test]
async fn machine_owns_transcript_edit_admission_verdict() {
    use crate::meerkat_machine::dsl::TranscriptEditAdmissionKind as Verdict;

    let adapter = MeerkatMachine::ephemeral();
    let session_id = SessionId::new();
    adapter
        .register_session(session_id.clone())
        .await
        .expect("register session");

    let verdict = |runtime_running, has_active_inputs| {
        let adapter = &adapter;
        let session_id = session_id.clone();
        async move {
            adapter
                .resolve_transcript_edit_admission(&session_id, runtime_running, has_active_inputs)
                .await
                .expect("machine must emit a transcript-edit admission verdict")
        }
    };

    // Idle with no active inputs is the only admissible combination.
    assert_eq!(verdict(false, false).await, Verdict::Admissible);

    // Running OR active-inputs => denied busy (the disjunction).
    assert_eq!(verdict(true, false).await, Verdict::DeniedBusy);
    assert_eq!(verdict(false, true).await, Verdict::DeniedBusy);
    assert_eq!(verdict(true, true).await, Verdict::DeniedBusy);
}
